const LANDMARKS_SOUTHWEST = [

// ═══════════════════════════════════════════════════════════
// CLARK COUNTY, NEVADA
// ═══════════════════════════════════════════════════════════

{ name:"Las Vegas Strip", county:"Clark, NV", emoji:"🎰", lat:36.1147, lon:-115.1728, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Las_Vegas_Strip_at_night%2C_January_2016.jpg/320px-Las_Vegas_Strip_at_night%2C_January_2016.jpg", fact:"The Las Vegas Strip has served as the backdrop for over <em>500 major Hollywood productions</em>, including Ocean's Eleven, Fear and Loathing in Las Vegas, and The Hangover. Its four-mile stretch of neon generates more filmed content per square mile than any other location in the American West." },
{ name:"Bellagio Hotel and Fountains", county:"Clark, NV", emoji:"⛲", lat:36.1126, lon:-115.1767, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Bellagio_fountains_1.jpg/320px-Bellagio_fountains_1.jpg", fact:"The climactic heist scene of <em>Ocean's Eleven</em> was filmed at the Bellagio's iconic fountains, which use 1,214 individual jets capable of shooting water 460 feet into the air. The fountains have since appeared in dozens of productions and music videos, becoming perhaps the most filmed hotel exterior in cinema history." },
{ name:"Fremont Street Experience", county:"Clark, NV", emoji:"💡", lat:36.1699, lon:-115.1420, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"Fremont Street's <em>1,500-foot LED canopy</em> is the largest single video screen in the world, suspended 90 feet above the original gambling district that predates the Strip by decades. The Golden Nugget here opened in 1946 and its vintage neon sign is one of the most photographed in America." },
{ name:"Hoover Dam", county:"Clark, NV", emoji:"🏗", lat:36.0160, lon:-114.7377, cat:"Historic Infrastructure", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Hoover Dam, completed in <em>1936</em>, was the largest concrete structure ever built at the time and has appeared in Superman, Transformers, and dozens of disaster films. Its construction killed 112 workers and created Lake Mead, the largest reservoir by volume in the United States." },
{ name:"Lake Mead National Recreation Area", county:"Clark, NV", emoji:"💧", lat:36.1552, lon:-114.7420, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Lake Mead supplies drinking water to <em>25 million people</em> in Nevada, Arizona, and California, and as drought has lowered water levels in recent years, a sunken WWII-era landing craft and several ghost towns have re-emerged from the depths. The reservoir's dramatic red canyon walls have provided backdrops for numerous film productions." },
{ name:"Red Rock Canyon National Conservation Area", county:"Clark, NV", emoji:"🏜", lat:36.1356, lon:-115.4277, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Red Rock Canyon's Aztec sandstone formations were deposited as ancient <em>sand dunes 180 million years ago</em>, then tilted and uplifted by the same forces that created the Rocky Mountains. The canyon has doubled as alien landscapes in dozens of sci-fi and Western productions." },
{ name:"Valley of Fire State Park", county:"Clark, NV", emoji:"🔥", lat:36.4630, lon:-114.5255, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Valley of Fire's blazing red Aztec sandstone formations appear to be on fire at sunrise and sunset and served as a filming location for <em>Star Trek Generations</em> and numerous other sci-fi productions. The park also contains 3,000-year-old Ancestral Puebloan petroglyphs at Atlatl Rock." },
{ name:"The Venetian Resort Las Vegas", county:"Clark, NV", emoji:"🎭", lat:36.1210, lon:-115.1696, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b9/The_Venetian_Las_Vegas.jpg/320px-The_Venetian_Las_Vegas.jpg", fact:"The Venetian opened in <em>1999</em> on the site of the legendary Sands Hotel, where the original Rat Pack filmed Ocean's 11 in 1960 — a film that launched Las Vegas's movie mythology. The resort's replica Grand Canal and St. Mark's Square have appeared in The Italian Job and numerous television productions." },
{ name:"MGM Grand Las Vegas", county:"Clark, NV", emoji:"🦁", lat:36.1021, lon:-115.1698, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/MGM_Grand_Las_Vegas.jpg/320px-MGM_Grand_Las_Vegas.jpg", fact:"The MGM Grand, with its <em>6,852 rooms</em> the largest single hotel complex in the United States, has hosted more championship boxing matches than any venue in history and served as a central location in Rain Man, The Hangover, and numerous other productions. Its famous lion logo references MGM's golden age of Hollywood film production." },
{ name:"Caesars Palace Las Vegas", county:"Clark, NV", emoji:"🏛", lat:36.1162, lon:-115.1745, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Caesars_Palace_Las_Vegas.jpg/320px-Caesars_Palace_Las_Vegas.jpg", fact:"Caesars Palace opened in <em>1966</em> and immediately became one of the most filmed hotel exteriors in Hollywood history, appearing in Rain Man, The Hangover, Rocky IV, and Evel Knievel's legendary 1967 fountain jump. The hotel's Roman-themed architecture was intentionally designed to evoke the glamour of Hollywood's Golden Age." },
{ name:"Neon Museum Las Vegas", county:"Clark, NV", emoji:"✨", lat:36.1776, lon:-115.1350, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Neon_Museum_Las_Vegas.jpg/320px-Neon_Museum_Las_Vegas.jpg", fact:"The Neon Museum's outdoor 'boneyard' preserves over <em>200 retired neon signs</em> from Las Vegas's golden era, including the original signs from the Stardust, Sahara, and Caesars Palace. The museum has become an increasingly popular film and photography location, its ghostly luminescence appearing in numerous music videos and indie films." },
{ name:"Las Vegas Natural History Museum", county:"Clark, NV", emoji:"🦕", lat:36.1841, lon:-115.1386, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Las Vegas Natural History Museum houses a <em>35-foot animatronic T. rex</em> and extensive exhibits on the Mojave Desert ecosystem that surrounds the city, reminding visitors that beneath the neon lies one of the most ecologically rich desert environments in North America. The museum's collection includes ancient megafauna fossils excavated from the Las Vegas Valley." },
{ name:"Springs Preserve Las Vegas", county:"Clark, NV", emoji:"🌿", lat:36.1716, lon:-115.1894, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Springs Preserve marks the site of the <em>original Las Vegas Springs</em> — the artesian water source that sustained the Paiute people and drew Mormon settlers and later railroad workers to establish what became Las Vegas. The springs dried up in 1962 from groundwater pumping, ending the natural water source that had sustained life here for thousands of years." },
{ name:"Nevada State Museum Las Vegas", county:"Clark, NV", emoji:"🏛", lat:36.1020, lon:-115.1765, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Nevada State Museum at the Springs Preserve tells the complete story of Nevada from its <em>Pleistocene megafauna</em> through the nuclear testing era at the Nevada Test Site, including artifacts from the Atomic Age that defined Southern Nevada's 20th-century identity. The museum's collection includes a replica of the underground nuclear test tunnels that honeycombed the desert north of Las Vegas." },
{ name:"Atomic Testing Museum Las Vegas", county:"Clark, NV", emoji:"☢", lat:36.1173, lon:-115.1441, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Nevada's <em>Nevada Test Site</em> hosted 928 nuclear tests between 1951 and 1992, and Las Vegas tourists in the 1950s could watch mushroom clouds rise over the desert from rooftop casino bars. The Atomic Testing Museum preserves this surreal chapter of American history through artifacts, declassified films, and a ground zero simulation room." },
{ name:"The Mob Museum Las Vegas", county:"Clark, NV", emoji:"🕵", lat:36.1726, lon:-115.1406, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"The Mob Museum occupies the <em>former Federal Courthouse</em> where the Kefauver Committee held its 1950 hearings into organized crime — the same hearings that put the mob's control of Las Vegas on national television for the first time. The museum's collection includes the actual brick wall from the St. Valentine's Day Massacre garage in Chicago." },
{ name:"Luxor Hotel and Sphinx", county:"Clark, NV", emoji:"🔺", lat:36.0953, lon:-115.1762, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Luxor_Las_Vegas.jpg/320px-Luxor_Las_Vegas.jpg", fact:"The Luxor's <em>39-story black glass pyramid</em> projects the world's strongest beam of light from its apex — visible from aircraft 275 miles away and from space on clear nights. The hotel's interior atrium is the largest in the world, and its design was so distinctive it appeared in the disaster film 2012 as one of the world's landmarks destroyed by catastrophe." },
{ name:"Paris Las Vegas Hotel", county:"Clark, NV", emoji:"🗼", lat:36.1124, lon:-115.1701, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Caesars_Palace_Las_Vegas.jpg/320px-Caesars_Palace_Las_Vegas.jpg", fact:"Paris Las Vegas features a <em>half-scale replica Eiffel Tower</em> that stands 541 feet tall and offers views of the entire Strip from an observation deck — a surreal experience that perfectly captures Las Vegas's identity as a city of simulated worlds. The hotel's Arc de Triomphe, Louvre facade, and hot air balloon are all built to the same 50% scale." },
{ name:"Stratosphere Tower Las Vegas", county:"Clark, NV", emoji:"🗼", lat:36.1473, lon:-115.1556, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"The Stratosphere Tower stands <em>1,149 feet tall</em>, making it the tallest freestanding observation tower in the United States, and its thrill rides at the summit include a roller coaster and a ride that hangs passengers over the edge of the building. The tower's distinctive shape has made it one of Las Vegas's most recognizable skyline elements in countless film productions." },
{ name:"National Finals Rodeo — Thomas & Mack Center", county:"Clark, NV", emoji:"🤠", lat:36.1016, lon:-115.1398, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Las Vegas has hosted the <em>National Finals Rodeo</em> every December since 1985, bringing 170,000 cowboys and fans to the city and generating over $600 million in economic activity — more than any single sporting event in Nevada history. The NFR transformed Las Vegas from a gambling city into the entertainment capital of the American West." },
{ name:"Old Las Vegas Mormon Fort State Historic Park", county:"Clark, NV", emoji:"🏚", lat:36.1763, lon:-115.1335, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"The Old Mormon Fort, built in <em>1855</em>, is the oldest non-Native American structure in Nevada and the founding settlement of what became Las Vegas — a mission established by Mormon pioneers attempting to maintain a supply route between Salt Lake City and Los Angeles. The fort's adobe walls were reconstructed from the original foundations discovered beneath a later railroad facility." },
{ name:"Las Vegas Motor Speedway", county:"Clark, NV", emoji:"🏎", lat:36.2722, lon:-115.0106, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Las Vegas Motor Speedway hosts two <em>NASCAR Cup Series races</em> annually and has been a filming location for Days of Thunder, Driven, and numerous car commercials that exploit the desert backdrop's dramatic visual contrast. The facility's 1.5-mile oval and dragstrip attract over 200,000 racing fans per year to the desert north of Las Vegas." },
{ name:"Mojave Desert — Las Vegas Valley", county:"Clark, NV", emoji:"🌵", lat:36.2500, lon:-115.2500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"The Las Vegas Valley sits in the <em>Mojave Desert</em>, the smallest and hottest of America's four deserts, where summer temperatures regularly exceed 115°F and the average annual rainfall is just 4.2 inches. The desert's Joshua trees, which can live 500 years, were named by Mormon pioneers who saw in their outstretched branches the prophet Joshua pointing the way to the promised land." },
{ name:"Nevada Test Site — Mercury Highway", county:"Clark, NV", emoji:"☢", lat:36.6230, lon:-115.9930, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Nevada Test and Training Range, visible from the highway north of Las Vegas, is where the United States detonated <em>928 nuclear weapons</em> between 1951 and 1992 — a program so publicly visible that Las Vegas marketed itself as the best place to watch atomic blasts. The test site's Sedan Crater, created by a 104-kiloton device in 1962, is the largest man-made crater in the United States." },
{ name:"Boulder City Historic District", county:"Clark, NV", emoji:"🏘", lat:35.9786, lon:-114.8328, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Boulder City was built from scratch in <em>1931</em> as a federal government company town for Hoover Dam construction workers — and uniquely among Nevada cities, it was dry from its founding and remains the only city in Nevada where gambling is still prohibited. The town's Art Deco buildings, including the historic Boulder Dam Hotel, are some of the finest examples of New Deal architecture in the Southwest." },
{ name:"Ethel M Chocolate Factory and Botanical Cactus Garden", county:"Clark, NV", emoji:"🍫", lat:36.0467, lon:-115.0411, cat:"Industrial", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Ethel M Chocolates was founded by Forrest Mars Sr. in <em>1981</em> in Henderson, Nevada — the same Mars family that created M&Ms, Snickers, and Milky Way — and the factory tour is one of the most popular free attractions in the Las Vegas Valley. The adjacent botanical cactus garden features over 300 species of cacti and succulents illuminated at Christmas with over a million lights." },
{ name:"Henderson Bird Viewing Preserve", county:"Clark, NV", emoji:"🦅", lat:35.9825, lon:-115.0644, cat:"Wildlife Area", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Henderson Bird Viewing Preserve, built around nine sewage treatment ponds, has become one of the <em>premier birding destinations</em> in the Mojave Desert, attracting over 200 species of migratory birds that use its water as an oasis stop. The preserve demonstrates how even industrial water treatment facilities can create unexpected wildlife sanctuaries in the desert." },
{ name:"Clark County Museum", county:"Clark, NV", emoji:"🏛", lat:35.9958, lon:-114.9839, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Clark County Museum preserves the history of Southern Nevada from the <em>Ancestral Puebloan era</em> through the atomic age, including a Heritage Street of relocated historic buildings from Las Vegas's earliest decades. The museum's collection of photographs documents the transformation of a small railroad town into the entertainment capital of the world." },
{ name:"Floyd Lamb Park at Tule Springs", county:"Clark, NV", emoji:"🦢", lat:36.3078, lon:-115.2219, cat:"Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Tule Springs was a <em>Pleistocene-era oasis</em> where mammoths, giant ground sloths, and American camels came to drink 50,000 years ago — their bones were discovered during construction of the park's ponds in the 1960s. The park's springs have supported human habitation for 11,000 years and the peacocks that roam freely through its grounds have become one of Las Vegas's most unexpected wildlife encounters." },
{ name:"Aliante Nature Discovery Park", county:"Clark, NV", emoji:"🌵", lat:36.2861, lon:-115.1744, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Aliante Nature Discovery Park preserves a small but significant <em>fossil trackway site</em> where dinosaur footprints are embedded in ancient mudstone, one of the few such sites accessible to the public in Southern Nevada. The park's interpretive displays explain how the Las Vegas Valley was once a lush subtropical forest before tectonic uplift created the desert environment." },
{ name:"Sloan Canyon National Conservation Area", county:"Clark, NV", emoji:"🪨", lat:35.9369, lon:-115.0497, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Sloan Canyon contains over <em>1,700 individual petroglyph panels</em> created by the Ancestral Puebloan and Southern Paiute peoples over a period of 10,000 years — one of the largest concentrations of rock art in the Mojave Desert. The canyon's remote location has protected it from vandalism and it remains one of the most pristine archaeological sites in Southern Nevada." },
{ name:"Whitney Mesa Nature Preserve", county:"Clark, NV", emoji:"🦎", lat:36.0528, lon:-115.0278, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Whitney Mesa is a rare <em>undeveloped desert mesa</em> within the urban Las Vegas Valley, supporting a population of Gila monsters — the only venomous lizard native to the United States — along with desert tortoises and dozens of Mojave Desert plant species. The preserve is surrounded by suburban development on all sides but has been protected since the 1990s as a biodiversity island." },
{ name:"Las Vegas Wash Wetlands", county:"Clark, NV", emoji:"🌿", lat:36.1258, lon:-114.9508, cat:"Wetlands", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Las Vegas Wash, which carries treated wastewater and urban runoff from the city to Lake Mead, has been <em>restored with native wetland vegetation</em> that now supports over 160 species of birds in the heart of one of America's fastest-growing metro areas. The wash's 12-mile trail system offers one of the most unexpected natural escapes in the Las Vegas Valley." },
{ name:"Willow Beach National Fish Hatchery", county:"Clark, NV", emoji:"🐟", lat:35.8597, lon:-114.6561, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Willow Beach Hatchery, located on the Arizona side of the Colorado River below Hoover Dam, raises <em>rainbow trout and razorback suckers</em> in the cold water released from the dam's power turbines. The hatchery's razorback sucker program is a critical effort to save one of the most endangered fish in North America, whose population collapsed after the dam altered the Colorado's natural flood and drought cycles." },
{ name:"Railroad Pass Hotel and Casino", county:"Clark, NV", emoji:"🚂", lat:35.9928, lon:-114.9222, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Railroad Pass Hotel, opened in <em>1931</em>, is the oldest continuously operating casino in Nevada — predating even the famous casinos of the Las Vegas Strip. It was built to serve the workers building Hoover Dam and its neon sign, one of the oldest in Nevada, was declared a historic landmark." },
{ name:"Eldorado Valley — Nevada Solar One", county:"Clark, NV", emoji:"☀", lat:35.7981, lon:-114.9828, cat:"Energy", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Nevada Solar One in the Eldorado Valley was one of the <em>first large-scale concentrating solar power plants</em> in the world when it opened in 2007, using 760 parabolic trough collectors spread over 400 acres to generate enough electricity to power 14,000 homes. The Mojave Desert's 300+ sunny days per year make it one of the premier solar energy regions in the world." },
{ name:"Historic Five — Las Vegas Sands Hotel Site", county:"Clark, NV", emoji:"🎲", lat:36.1175, lon:-115.1714, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b9/The_Venetian_Las_Vegas.jpg/320px-The_Venetian_Las_Vegas.jpg", fact:"The site of the original Sands Hotel, now occupied by The Venetian, was where Frank Sinatra, Dean Martin, Sammy Davis Jr., Peter Lawford, and Joey Bishop filmed <em>Ocean's 11 in 1960</em> — performing their famous Rat Pack show by night and filming by day. The Sands was demolished in 1996 and the footage of its implosion was used in the remake Ocean's Eleven starring George Clooney." },
{ name:"The Mirage Volcano", county:"Clark, NV", emoji:"🌋", lat:36.1213, lon:-115.1742, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Caesars_Palace_Las_Vegas.jpg/320px-Caesars_Palace_Las_Vegas.jpg", fact:"The Mirage's artificial volcano, which erupts every hour after dark with <em>real fire and water effects</em>, was the attraction that triggered the modern era of themed mega-resorts when it opened in 1989. Steve Wynn's $630 million Mirage transformed the Strip from a collection of simple casinos into a destination for spectacle, inspiring every resort that followed." },
{ name:"Nevada State Railroad Museum — Boulder City", county:"Clark, NV", emoji:"🚂", lat:35.9803, lon:-114.8406, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Nevada State Railroad Museum preserves the <em>historic railroad equipment</em> used to build Hoover Dam, including the original locomotives that hauled millions of tons of gravel and concrete through the Black Canyon. The museum's collection represents one of the most complete records of Depression-era industrial railroading in the American West." },
{ name:"Bootleg Canyon Mountain Bike Park", county:"Clark, NV", emoji:"🚵", lat:35.9792, lon:-114.8756, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Bootleg Canyon above Boulder City is considered one of the <em>top ten mountain bike destinations</em> in the United States, with 35 miles of trails carved through desert terrain overlooking Lake Mead and Hoover Dam. The park's exposed volcanic rock and dramatic elevation changes have made it a favorite location for extreme sports films and photography." },
{ name:"Calico Basin Red Rock Overlook", county:"Clark, NV", emoji:"🏜", lat:36.1489, lon:-115.4100, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Calico Basin sits at the base of Red Rock Canyon's most dramatic escarpment, where <em>red and cream sandstone cliffs</em> rise 3,000 feet directly from the valley floor in one of the most visually striking geological transitions in North America. The basin's spring-fed stream supports a riparian oasis of cottonwood and willow trees surrounded by Mojave Desert on all sides." },
{ name:"Searchlight Historic District", county:"Clark, NV", emoji:"⛏", lat:35.4697, lon:-114.9208, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Searchlight was once the <em>largest city in Nevada</em> during the gold and silver mining boom of 1898-1910, with a population of 1,500 and its own railroad spur. The town was the birthplace of former U.S. Senate Majority Leader Harry Reid and its abandoned mine shafts and mill ruins remain one of the most intact early Nevada mining landscapes." },
{ name:"Colorado River — Black Canyon Water Trail", county:"Clark, NV", emoji:"🚣", lat:36.0047, lon:-114.7356, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Black Canyon Water Trail below Hoover Dam offers <em>12 miles of kayaking</em> through one of the most dramatic canyon landscapes in the Southwest, where the cold water released from deep within the dam maintains a constant 55°F temperature year-round. The canyon's hot springs, accessible only by water, were used by Native Americans for thousands of years before the dam was built." },
{ name:"Nevada Test and Training Range — Groom Lake Area", county:"Clark, NV", emoji:"🛸", lat:37.2350, lon:-115.8111, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Area 51, officially the Nevada Test and Training Range at Groom Lake, has been the subject of more <em>conspiracy theories and science fiction films</em> than any other military installation in the world — appearing in Independence Day, Men in Black, and countless other productions. The base has been used for testing classified aircraft since the U-2 spy plane in the 1950s and its true activities remain classified." },
{ name:"Lake Las Vegas Resort", county:"Clark, NV", emoji:"🏖", lat:36.1117, lon:-114.9608, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Lake Las Vegas is a <em>320-acre private lake</em> created in the 1990s by damming Las Vegas Wash in Henderson, surrounded by luxury resorts and private homes that create the surreal image of a Riviera-style lakefront community in the middle of the Mojave Desert. The lake has been used as a filming location for productions seeking a Mediterranean backdrop without leaving Nevada." },
{ name:"Wetlands Park Las Vegas", county:"Clark, NV", emoji:"🦆", lat:36.1258, lon:-115.0547, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"Clark County Wetlands Park is the largest <em>urban wetland in Nevada</em>, covering 2,900 acres along the Las Vegas Wash and supporting populations of great blue herons, black-crowned night herons, and dozens of other waterbird species within view of the Las Vegas Strip. The park's existence demonstrates how water reclamation can create rich habitat in the most unexpected urban environments." },

// ── Clark County additional entries ──
{ name:"The Strat — Former Stratosphere Tower", county:"Clark, NV", emoji:"🎢", lat:36.1473, lon:-115.1556, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"The Strat's rooftop thrill rides include SkyJump, a <em>855-foot controlled free fall</em> down the outside of the tower that is the highest commercial jump in the world. The tower's observation deck at 1,149 feet offers views stretching to Death Valley, the Spring Mountains, and on clear days all the way to Mount Charleston." },
{ name:"Container Park — Downtown Las Vegas", county:"Clark, NV", emoji:"🛍", lat:36.1694, lon:-115.1378, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"Container Park is an outdoor shopping and entertainment venue built from <em>repurposed shipping containers</em> in the heart of the Downtown Las Vegas revitalization zone, anchored by a 55-foot praying mantis sculpture that shoots fire. The project was funded by Zappos founder Tony Hsieh as part of his $350 million Downtown Project to transform Fremont East into a technology and arts hub." },
{ name:"Nevada Governor's Mansion Historic Site", county:"Clark, NV", emoji:"🏛", lat:36.1699, lon:-115.1420, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"The historic buildings of downtown Las Vegas near Fremont Street preserve the city's <em>pre-casino commercial identity</em> from the 1910s and 1920s, when Las Vegas was primarily a railroad and supply town serving Nevada's ranching industry. Several buildings from this era survive amid the neon, their brick facades visible above the modern signage." },
{ name:"Shark Reef Aquarium — Mandalay Bay", county:"Clark, NV", emoji:"🦈", lat:36.0908, lon:-115.1764, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Luxor_Las_Vegas.jpg/320px-Luxor_Las_Vegas.jpg", fact:"Shark Reef Aquarium at Mandalay Bay holds <em>2,000 animals</em> in 1.3 million gallons of water, including a rare collection of sawfish, golden crocodiles, and a walk-through tunnel where sharks swim overhead. The aquarium is one of the finest in the American West and its research programs contribute to shark conservation science." },
{ name:"Discovery Children's Museum — Las Vegas", county:"Clark, NV", emoji:"🔬", lat:36.1778, lon:-115.1408, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Neon_Museum_Las_Vegas.jpg/320px-Neon_Museum_Las_Vegas.jpg", fact:"The Discovery Children's Museum, housed in a striking three-story building in Symphony Park near downtown Las Vegas, is built around a <em>nine-story pinnacle tower</em> filled with hands-on science exhibits. The museum's location adjacent to the Cleveland Clinic Lou Ruvo Center for Brain Health created one of the most architecturally dramatic cultural campuses in Nevada." },
{ name:"Lou Ruvo Center for Brain Health — Las Vegas", county:"Clark, NV", emoji:"🧠", lat:36.1778, lon:-115.1447, cat:"Historic Building", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Neon_Museum_Las_Vegas.jpg/320px-Neon_Museum_Las_Vegas.jpg", fact:"Frank Gehry's Cleveland Clinic Lou Ruvo Center for Brain Health is one of the <em>most daring pieces of architecture</em> in Nevada — a crumpled steel building that appears to be melting into the desert, built to provide cutting-edge research and treatment for Alzheimer's disease. The building's deliberately disorienting form is intended to evoke the confusion of cognitive decline." },
{ name:"Pinball Hall of Fame — Las Vegas", county:"Clark, NV", emoji:"🎮", lat:36.0853, lon:-115.1514, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Luxor_Las_Vegas.jpg/320px-Luxor_Las_Vegas.jpg", fact:"The Pinball Hall of Fame houses the <em>largest collection of working pinball machines</em> in the world, with over 900 machines spanning eight decades of pinball history, all playable for 25 cents. Founder Tim Arnold has spent 40 years collecting and restoring machines and donates all profits to the Salvation Army." },
{ name:"Las Vegas Ballpark — Summerlin", county:"Clark, NV", emoji:"⚾", lat:36.1956, lon:-115.3017, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Red_Rock_Canyon_NCA.jpg/320px-Red_Rock_Canyon_NCA.jpg", fact:"Las Vegas Ballpark, opened in 2019 in the master-planned community of Summerlin, is consistently ranked as one of the <em>finest minor league baseball parks</em> in America, with a pool beyond the outfield wall and views of the Spring Mountains. The park's design was influenced by the natural desert landscape and its red rock color palette connects it visually to Red Rock Canyon visible in the distance." },
{ name:"Hemenway Valley Park — Boulder City", county:"Clark, NV", emoji:"🦅", lat:36.0058, lon:-114.8386, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Hemenway Valley Park in Boulder City is the best place in the Las Vegas area to observe <em>migrating and wintering raptors</em>, particularly ferruginous hawks and prairie falcons that hunt the open desert grasslands each winter. The park's location at the edge of the Mojave Desert makes it a critical waypoint for birds traveling the Pacific Flyway." },
{ name:"Hoover Dam Bypass Bridge — Mike O'Callaghan–Pat Tillman Memorial Bridge", county:"Clark, NV", emoji:"🌉", lat:35.9986, lon:-114.7375, cat:"Historic Infrastructure", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The O'Callaghan-Tillman Memorial Bridge, completed in <em>2010</em>, is the highest concrete arch bridge in the Western Hemisphere at 890 feet above the Colorado River, and its construction required some of the most innovative engineering techniques ever used on an American highway project. The bridge carries US-93 over Black Canyon and allows visitors to walk across on a pedestrian path with dramatic views of Hoover Dam below." },
{ name:"Nevada State Museum — Las Vegas Art District", county:"Clark, NV", emoji:"🎨", lat:36.1641, lon:-115.1453, cat:"Arts", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Neon_Museum_Las_Vegas.jpg/320px-Neon_Museum_Las_Vegas.jpg", fact:"The Las Vegas Arts District centered on Charleston Boulevard has transformed a formerly industrial neighborhood into a <em>gallery district, studio complex, and performance venue</em> that represents the city's creative counterculture. The monthly First Friday art walk draws thousands of visitors to the district and has been credited with seeding the revival of downtown Las Vegas." },
{ name:"Sunset Park Las Vegas", county:"Clark, NV", emoji:"🌅", lat:36.0714, lon:-115.1228, cat:"Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Sunset Park's 320-acre lake, created from treated wastewater, is one of the <em>most popular recreation spots</em> in the Las Vegas Valley and hosts competitive rowing, remote control sailboat racing, and radio-controlled airplane flying — activities that seem incongruous in the middle of the Mojave Desert but reflect Las Vegas's determination to recreate suburban amenities in the desert. The park's size and central location have made it a filming location for several television productions set in suburban America." },
{ name:"Clark County Shooting Complex", county:"Clark, NV", emoji:"🎯", lat:36.3528, lon:-115.0033, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Clark County Shooting Complex is the <em>largest public shooting facility in the United States</em>, with 150 lanes for pistol, rifle, and shotgun shooting spread across 2,900 acres of Mojave Desert. The facility hosts the annual Bianchi Cup, considered the World Series of practical shooting, and its remote desert location provides natural backstops for every shooting discipline." },
{ name:"Lost City Museum — Overton Nevada", county:"Clark, NV", emoji:"🏺", lat:36.5350, lon:-114.4431, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"The Lost City Museum in Overton preserves artifacts from the <em>Ancestral Puebloan Basketmaker culture</em> that flourished in the Moapa Valley from 300 BCE to 1150 CE, including pit house reconstructions and thousands of pottery fragments excavated before Lake Mead flooded the original site. The museum is built on the original excavation site and its foundations incorporate original adobe walls from the ancient village." },
{ name:"Valley of Fire — Elephant Rock", county:"Clark, NV", emoji:"🐘", lat:36.4547, lon:-114.5069, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Elephant Rock in Valley of Fire is one of Nevada's most recognizable natural sculptures — an <em>enormous red sandstone formation</em> shaped unmistakably like a sitting elephant that has become one of the most photographed geological features in the state. The formation's accessibility from a short trail has made it a popular location for family photographs and film productions." },
{ name:"Mike O'Callaghan Pat Tillman Memorial Bridge Walkway", county:"Clark, NV", emoji:"🚶", lat:35.9986, lon:-114.7375, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The pedestrian walkway on the Hoover Dam Bypass Bridge offers the most dramatic <em>aerial view of Hoover Dam</em> available to the public, looking straight down 890 feet to the dam's face and the Colorado River below. The walkway has become one of the most popular photographic vantage points in Nevada and features interpretive displays about Pat Tillman, the NFL player who left his career to join the Army Rangers after 9/11." },

// ═══════════════════════════════════════════════════════════
// MOHAVE COUNTY, ARIZONA
// ═══════════════════════════════════════════════════════════

{ name:"Kingman — Historic Route 66 Downtown", county:"Mohave, AZ", emoji:"🛤", lat:35.1894, lon:-114.0530, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman sits at the heart of the longest remaining stretch of <em>original Route 66</em>, the Mother Road that carried millions of Americans westward during the Great Depression and Dust Bowl migration immortalized in Steinbeck's The Grapes of Wrath. The town's historic downtown, largely unchanged since the 1940s, has appeared in numerous road trip films and documentaries celebrating America's most storied highway." },
{ name:"Route 66 Museum Kingman", county:"Mohave, AZ", emoji:"🚗", lat:35.1897, lon:-114.0583, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Route 66 Museum in Kingman is one of the finest archives of <em>Mother Road memorabilia</em> in existence, preserving the neon signs, gas station artifacts, and personal stories of the millions who traveled America's Main Street between 1926 and 1985. The museum's collection includes a 1940s-era diner counter and a fully restored vintage service station that transports visitors back to the golden age of American road culture." },
{ name:"Hulapai Mountain Park", county:"Mohave, AZ", emoji:"🌲", lat:35.0917, lon:-113.8958, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Hualapai Mountain Park rises to <em>8,417 feet</em>, making it the highest point in Mohave County and a cool forested escape from the desert below, where ponderosa pine and white fir grow at elevations that receive 25 inches of precipitation per year. The park's dramatic granite formations and panoramic views of the Colorado River valley have made it a popular filming location for productions seeking a Rocky Mountain aesthetic in the Southwest." },
{ name:"Grand Canyon West — Skywalk", county:"Mohave, AZ", emoji:"🌉", lat:36.0144, lon:-113.8125, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Grand Canyon Skywalk, built on Hualapai tribal land and opened in <em>2007</em>, extends 70 feet beyond the canyon rim on a glass-bottomed horseshoe-shaped bridge 4,000 feet above the Colorado River. The Skywalk was designed by a Las Vegas architect and its dramatic construction — requiring helicopter transport of every component — was itself the subject of a Discovery Channel documentary." },
{ name:"Hualapai Nation — Diamond Creek Road", county:"Mohave, AZ", emoji:"🪶", lat:35.9461, lon:-113.6783, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Diamond Creek Road is the <em>only road in the Grand Canyon</em> that descends to the Colorado River, crossing 23 miles of Hualapai tribal land to reach the canyon bottom where river rafters end their trips. The Hualapai people have lived in the Grand Canyon region for centuries and their Diamond Creek site was used as a camp by Lieutenant Joseph Ives during the first American expedition into the canyon in 1857." },
{ name:"Oatman — Historic Gold Mining Town", county:"Mohave, AZ", emoji:"🫏", lat:34.8242, lon:-114.4178, cat:"Historic Town", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Oatman's wild burros — descendants of pack animals abandoned by gold miners — roam freely through the town's <em>Old West main street</em> and have become the town's most famous attraction, approaching visitors for food and appearing in photographs worldwide. Clark Gable and Carole Lombard honeymooned at the Oatman Hotel in 1939 after their secret wedding in Kingman, and their suite is preserved as a museum." },
{ name:"Lake Havasu City — London Bridge", county:"Mohave, AZ", emoji:"🌉", lat:34.4839, lon:-114.3286, cat:"Historic Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"The original <em>London Bridge</em>, built in 1831 and sold by the City of London in 1968, was dismantled stone by stone, shipped to Arizona, and reassembled over a man-made channel in the desert — one of the most audacious real estate promotions in history. Developer Robert McCulloch purchased the bridge for $2.46 million to anchor a planned city in the Mohave Desert, and Lake Havasu City has since grown to 55,000 residents." },
{ name:"Lake Havasu State Park", county:"Mohave, AZ", emoji:"🏄", lat:34.4894, lon:-114.3619, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Lake Havasu, formed by Parker Dam on the Colorado River, has become one of the <em>premier water recreation destinations</em> in the American Southwest, drawing over 800,000 visitors per year to its 60 miles of shoreline for boating, swimming, and fishing. The lake's warm desert setting and proximity to Las Vegas have made it a favorite location for spring break gatherings and the backdrop for several reality television productions." },
{ name:"Chloride — Arizona's Oldest Silver Mining Town", county:"Mohave, AZ", emoji:"⛏", lat:35.4092, lon:-114.2064, cat:"Historic Town", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Chloride, founded in <em>1862</em>, is the oldest continuously inhabited mining town in Arizona, where silver, gold, and turquoise were extracted from the Cerbat Mountains until the 1940s. The town's murals painted directly onto the mountain rock face by artist Roy Purcell in the 1960s have become one of the most unusual public art installations in the Southwest." },
{ name:"Bullhead City — Davis Dam Historic Site", county:"Mohave, AZ", emoji:"💧", lat:35.1478, lon:-114.5686, cat:"Historic Infrastructure", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Davis Dam, completed in <em>1953</em>, was built to fulfill America's treaty obligation to deliver Colorado River water to Mexico and created Lake Mohave, a 67-mile reservoir between Hoover and Davis dams. The dam's construction brought thousands of workers to the previously uninhabited desert and created the twin cities of Bullhead City, Arizona and Laughlin, Nevada." },
{ name:"Laughlin — Colorado River Historic Casino Strip", county:"Mohave, AZ", emoji:"🎰", lat:35.1683, lon:-114.5747, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Laughlin was founded in <em>1966</em> by Don Laughlin, who purchased an abandoned bait shop on the Colorado River and built it into a casino resort that now anchors a gambling district attracting 3 million visitors annually. The Laughlin River Run motorcycle rally, held each April, is one of the largest motorcycle gatherings in the United States, drawing 50,000 riders to the desert." },
{ name:"Needles Highway — Historic Route 66 Corridor", county:"Mohave, AZ", emoji:"🛤", lat:34.8483, lon:-114.6147, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Needles stretch of Route 66 was the most dreaded section of the Mother Road for Depression-era Dust Bowl migrants, where temperatures regularly exceeded <em>120°F</em> and car radiators boiled over in the desert sun. John Steinbeck described this section of highway in The Grapes of Wrath as the approach to the promised land of California, both terrifying and hopeful." },
{ name:"Arizona Hot Springs — Black Canyon", county:"Mohave, AZ", emoji:"♨️", lat:35.9031, lon:-114.6722, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Arizona Hot Springs below Hoover Dam can only be reached by <em>kayak or a 6-mile round-trip hike</em> through a slot canyon, and the effort is rewarded by natural pools of 106°F water cascading down a red rock waterfall directly into the Colorado River. The springs have been used for thousands of years by the Southern Paiute people as a healing site." },
{ name:"Topock Gorge — Colorado River", county:"Mohave, AZ", emoji:"🌊", lat:34.7150, lon:-114.4789, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Topock Gorge is a <em>12-mile canyon</em> where the Colorado River cuts through volcanic rock formations to create one of the most scenic kayaking corridors in the Southwest, accessible only by water. The gorge's ancient petroglyphs, created by the Mohave people thousands of years ago, line the canyon walls and are among the finest examples of Colorado River rock art remaining." },
{ name:"McCulloch Bros. Ranch — Parker Strip", county:"Mohave, AZ", emoji:"🌵", lat:34.2983, lon:-114.1456, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"The Parker Strip along the lower Colorado River was developed into a string of resort communities in the <em>1950s and 1960s</em> by the same developer who built Lake Havasu City, creating a chain of waterfront communities that became popular weekend escapes for Phoenix and Los Angeles residents. The strip's dramatic desert canyon setting has been used as a filming location for boat racing films and commercials." },
{ name:"Kingman Army Air Field Historic Site", county:"Mohave, AZ", emoji:"✈️", lat:35.2594, lon:-113.9381, cat:"Historic Military", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Kingman Army Air Field trained over <em>35,000 aerial gunners</em> during World War II and was the site where thousands of surplus warplanes were scrapped after the war — the desert's dry climate perfectly preserved the aircraft until they could be processed. The base is also where Clark Gable trained as an aerial gunner after the death of Carole Lombard, and where he flew combat missions before returning to Hollywood." },
{ name:"Sitgreaves Pass — Historic Route 66 Summit", county:"Mohave, AZ", emoji:"🛤", lat:34.8833, lon:-114.3667, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Sitgreaves Pass at 3,550 feet is the highest point on Route 66 in Arizona, where the original highway's hairpin turns were so steep that <em>drivers had to back up their Model T Fords</em> to negotiate the switchbacks because reverse gear provided more torque than first. The pass's dramatic desert mountain scenery has made it one of the most photographed sections of the historic highway." },
{ name:"Hackberry General Store — Route 66", county:"Mohave, AZ", emoji:"🛣", lat:35.3672, lon:-113.7183, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Hackberry General Store, surrounded by <em>vintage gas pumps, signs, and automobiles</em> from the Route 66 era, is one of the most photographed stops on the historic highway and a pilgrimage site for road trip enthusiasts worldwide. The store's collection of Route 66 memorabilia, accumulated over decades, represents one of the finest outdoor museums of American road culture in existence." },
{ name:"White Hills Ghost Town", county:"Mohave, AZ", emoji:"🏚", lat:35.6381, lon:-114.3808, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Lake_Mead_National_Recreation_Area.jpg/320px-Lake_Mead_National_Recreation_Area.jpg", fact:"White Hills was a silver mining boomtown of <em>1,500 people in the 1890s</em> that was completely abandoned within a decade when the mines played out, leaving behind crumbling adobe walls and scattered mining equipment in the desert. The ghost town's isolation and photogenic ruins have made it a popular location for film productions seeking an authentic abandoned Western town." },
{ name:"Mohave Museum of History and Arts", county:"Mohave, AZ", emoji:"🏛", lat:35.1900, lon:-114.0528, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Mohave Museum preserves the history of one of Arizona's largest and least-populated counties, including <em>artifacts from the Hualapai, Mohave, and Hopi peoples</em> who have inhabited the region for thousands of years. The museum's Route 66 gallery documents the highway's transformation of Kingman from a remote railroad town into a celebrated stop on America's most storied road." },
{ name:"Powerhouse Visitor Center Kingman", county:"Mohave, AZ", emoji:"⚡", lat:35.1897, lon:-114.0583, cat:"Historic Building", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's Powerhouse Visitor Center occupies a <em>1907 electric power plant</em> that once supplied electricity to the entire region and now houses the Route 66 Museum, an electric vehicle charging station, and historic memorabilia celebrating the town's place on America's Mother Road. The building's original turbines are still visible through glass panels in the floor." },
{ name:"Cerbat Mountains — Mineral Park Mine", county:"Mohave, AZ", emoji:"⛏", lat:35.3556, lon:-114.1953, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Mineral Park Mine in the Cerbat Mountains was one of the <em>largest open-pit copper and turquoise mines</em> in Arizona history, producing over 400 million pounds of copper between its modern reopening in 1970 and closure in 1981. The mine's turquoise, known as Kingman Turquoise, is considered among the finest in the world and has been used in Native American jewelry for centuries." },
{ name:"Colorado River Indian Tribes Museum", county:"Mohave, AZ", emoji:"🪶", lat:34.1542, lon:-114.2842, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Colorado River Indian Tribes Museum in Parker preserves the cultural heritage of the <em>Mohave, Chemehuevi, Navajo, and Hopi peoples</em> who were relocated to the Colorado River Indian Reservation in the 1940s. The museum's collection of prehistoric pottery, basketry, and beadwork represents some of the finest examples of Colorado River Valley indigenous art in any public collection." },
{ name:"Bill Williams River National Wildlife Refuge", county:"Mohave, AZ", emoji:"🦅", lat:34.2564, lon:-114.0542, cat:"Wildlife Refuge", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"The Bill Williams River refuge protects the last significant <em>cottonwood-willow riparian forest</em> on the lower Colorado River, a habitat type that has been reduced to less than 5% of its original extent by water diversion and development. The refuge's dense vegetation supports the highest density of breeding birds in the Sonoran Desert region." },
{ name:"Havasu National Wildlife Refuge — Topock Marsh", county:"Mohave, AZ", emoji:"🦢", lat:34.7197, lon:-114.4894, cat:"Wildlife Refuge", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Topock Marsh within Havasu National Wildlife Refuge is one of the <em>most important migratory bird stopovers</em> in the American Southwest, where up to 350 species have been recorded during peak migration periods. The marsh's tule beds and open water are managed to mimic the natural flood-and-drought cycles of the pre-dam Colorado River." },
{ name:"Peach Springs — Hualapai Tribal Headquarters", county:"Mohave, AZ", emoji:"🪶", lat:35.5247, lon:-113.4233, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Peach Springs is the headquarters of the <em>Hualapai Nation</em>, whose reservation covers one million acres of northwestern Arizona including 108 miles of the Grand Canyon's South Rim — more Grand Canyon frontage than any other entity. The Hualapai operate the only road access to the bottom of the Grand Canyon and the famous glass-bottom Skywalk." },

// ── Mohave County additional entries ──
{ name:"Katharine Mine — Oatman Gold Road Historic District", county:"Mohave, AZ", emoji:"⛏", lat:34.8833, lon:-114.3667, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Gold Road Mine near Oatman produced <em>$1.8 million in gold</em> between 1902 and 1942, and the historic mill ruins and headframe are still visible along the original Route 66 alignment. The mine's story — bonanza discovery, boom, bust, and abandonment — mirrors the arc of dozens of Arizona mining towns along the Mother Road." },
{ name:"Moss Mine — Mohave County Historic Site", county:"Mohave, AZ", emoji:"🪨", lat:35.1500, lon:-114.3000, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Moss Mine, discovered in <em>1863</em> by Captain John Moss, was one of the richest gold and silver deposits in Arizona Territory and helped trigger the development of Mohave County's mining economy. The mine's adobe ruins and collapsed shaft timbers remain visible in the desert and represent some of the oldest American mining infrastructure in the Colorado River region." },
{ name:"Fort Mohave Historical Site", county:"Mohave, AZ", emoji:"🏚", lat:34.9717, lon:-114.5706, cat:"Historic Military", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Fort Mohave, established in <em>1859</em> on the Colorado River, was the primary U.S. Army post controlling the lower Colorado River crossing and protecting the wagon road to California during the Apache and Mohave Indian wars. The fort was abandoned in 1890 and its land converted to an Indian school; today the site is part of the Fort Mojave Indian Tribe's reservation." },
{ name:"Topock — Historic Route 66 Colorado River Crossing", county:"Mohave, AZ", emoji:"🌉", lat:34.7181, lon:-114.4917, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Topock was where Route 66 crossed the Colorado River on the <em>Old Trails Arch Bridge</em>, completed in 1916 as one of the first automobile bridges over the lower Colorado and the primary entry point into California for westbound travelers. The bridge is now a pedestrian walkway and National Historic Landmark, a rare surviving example of early 20th-century steel through-truss bridge construction." },
{ name:"Burro Creek Canyon Campground and Bridge", county:"Mohave, AZ", emoji:"🌊", lat:34.4761, lon:-113.3444, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Burro Creek Canyon is one of the most <em>surprising desert oases</em> in Arizona — a permanent stream flowing through a dramatic canyon of volcanic and granite rock that supports cottonwood trees, nesting raptors, and a remarkable diversity of desert wildlife in an otherwise stark landscape. The campground here is considered one of the finest primitive camping spots in western Arizona." },
{ name:"Wikieup — Bill Williams River Corridor", county:"Mohave, AZ", emoji:"🦅", lat:34.7061, lon:-113.5997, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Bill Williams River corridor near Wikieup is one of the <em>finest birding locations in Arizona</em>, where the river's cottonwood-willow gallery forest attracts migrating warblers, flycatchers, and vireos in spring and fall concentrations rivaling any in the Southwest. The corridor provides critical connectivity between the Sonoran and Mojave desert ecosystems." },
{ name:"Lake Mohave — Cottonwood Cove", county:"Mohave, AZ", emoji:"🚤", lat:35.4847, lon:-114.6869, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Lake Mohave, stretching <em>67 miles</em> between Hoover and Davis Dams through the Black Canyon, is one of the premier fishing and boating destinations in the American Southwest, famous for its rainbow and striped bass population. The lake's cold, clear water — kept at 55°F by releases from Hoover Dam — has created one of the most unusual fisheries in the desert Southwest." },
{ name:"Yucca — World War II Proving Ground Site", county:"Mohave, AZ", emoji:"💣", lat:34.8750, lon:-114.1500, cat:"Historic Military", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The desert around Yucca, Arizona was used as a <em>World War II military proving ground</em> where thousands of weapons, vehicles, and tactical maneuvers were tested in conditions similar to the North African theater where American forces were fighting Rommel's Afrika Korps. The remote desert landscape, unchanged by development, still contains unexploded ordnance in restricted areas." },
{ name:"Mohave Valley — Historic Mohave Tribe Territory", county:"Mohave, AZ", emoji:"🪶", lat:34.9000, lon:-114.5500, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Mohave Tribe has lived along the Colorado River for <em>at least 2,000 years</em>, farming the river's floodplain and developing one of the most distinctive pottery and bead-working traditions in the Southwest. The Mohave were among the few Native American peoples never conquered militarily — the U.S. Army eventually negotiated a peace treaty that allowed them to remain in their ancestral homeland." },
{ name:"Dolan Springs — Joshua Tree Forest", county:"Mohave, AZ", emoji:"🌵", lat:35.5947, lon:-114.2636, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Mohave Desert around Dolan Springs contains one of the <em>densest Joshua tree forests</em> in Arizona, where the iconic trees grow in groves that stretch to the horizon in the high desert above the Colorado River valley. Joshua trees can live over 500 years and their presence indicates the transition zone between the Mojave and Sonoran deserts." },
{ name:"Hualapai Mountain Road Scenic Drive", county:"Mohave, AZ", emoji:"🛤", lat:35.0917, lon:-113.8958, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The drive up Hualapai Mountain Road from Kingman passes through <em>five distinct plant communities</em> — from Sonoran Desert saguaro at the base to ponderosa pine at the summit — representing an ecological transition equivalent to driving from Mexico to Canada. The road's dramatic switchbacks and panoramic desert views have made it a popular location for automobile commercials and outdoor recreation films." },
{ name:"Kingman — Historic Santa Fe Railroad Depot", county:"Mohave, AZ", emoji:"🚂", lat:35.1897, lon:-114.0528, cat:"Historic Building", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's 1907 Santa Fe Railroad depot is one of the finest surviving examples of <em>Harvey House Mission Revival architecture</em> in Arizona, built to attract wealthy train travelers to the Southwest with its graceful arcades and tile roof. The depot served as the point where Route 66 and the railroad intersected, making Kingman a critical node in the transportation network of the American West." },
{ name:"White Rock Springs — Historic Watering Hole", county:"Mohave, AZ", emoji:"💧", lat:35.4000, lon:-114.0500, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"White Rock Springs was a <em>critical water source</em> on the historic Beale Wagon Road built in 1857-1858 by Lieutenant Edward Beale, who used 25 camels imported from the Middle East to test their usefulness in the American desert. The springs sustained travelers on the road that became a template for both the railroad and eventually Route 66." },
{ name:"Mohave Desert — Beale Road Historic Corridor", county:"Mohave, AZ", emoji:"🛤", lat:35.3000, lon:-113.8000, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Beale Wagon Road, surveyed in <em>1857</em> along the 35th parallel, was the first federal highway across Arizona and became the basis for the Atlantic and Pacific Railroad, which in turn became the route of Route 66. Lieutenant Beale's camels, imported from Tunisia and Egypt, successfully crossed the Mojave Desert but the Army lost interest in the experiment after the Civil War began." },
{ name:"Havasu Falls — Supai Village", county:"Mohave, AZ", emoji:"💦", lat:36.2553, lon:-112.6978, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Havasu Falls on the Havasupai Reservation plunges <em>100 feet</em> into a turquoise pool fed by travertine-filtered water that gives it an impossibly vivid blue-green color unlike any other waterfall in North America. The Havasupai people — whose name means 'people of the blue-green water' — have lived in Havasu Canyon for 800 years and the village of Supai is the most remote community in the contiguous United States." },
{ name:"Route 66 — Cool Springs Camp Historic Site", county:"Mohave, AZ", emoji:"🛣", lat:34.9031, lon:-114.2972, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Cool Springs Camp, rebuilt on the original foundation after the 1966 original was demolished, represents a <em>classic 1920s automobile camp</em> where weary travelers stopped to refuel, eat, and sleep during the long desert crossing on Route 66. The restored station's twin cylindrical gas pump islands and stone construction have been used in numerous automobile commercials and road trip documentaries." },

// ═══════════════════════════════════════════════════════════
// SAN JUAN COUNTY, UTAH — Little Hollywood & Monument Valley
// ═══════════════════════════════════════════════════════════

{ name:"Monument Valley Navajo Tribal Park", county:"San Juan, UT", emoji:"🏜", lat:36.9980, lon:-110.0985, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Monument Valley's three sandstone mittens — the West Mitten, East Mitten, and Merrick Butte — are the <em>most filmed landscape in cinema history</em>, appearing in Stagecoach, The Searchers, 2001: A Space Odyssey, Easy Rider, Back to the Future III, and Forrest Gump among hundreds of other productions. John Ford filmed seven Westerns here, establishing the buttes as the defining image of the American West." },
{ name:"John Ford's Point — Monument Valley", county:"San Juan, UT", emoji:"🎬", lat:36.9947, lon:-110.1119, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"John Ford's Point is the exact overlook where director John Ford positioned his camera for <em>The Searchers, Stagecoach, Fort Apache, and She Wore a Yellow Ribbon</em>, creating the definitive cinematic framing of Monument Valley that has been copied in hundreds of films. Ford is credited with singlehandedly establishing Monument Valley as the iconic American landscape through his 1939 filming of Stagecoach." },
{ name:"The Mittens and Merrick Butte", county:"San Juan, UT", emoji:"🧤", lat:36.9972, lon:-110.1011, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"The Mittens, rising <em>1,000 feet</em> from the valley floor, are composed of de Chelly sandstone deposited 270 million years ago when the Colorado Plateau was a vast coastal desert of towering dunes. The Navajo people call the formation Tsé Bii' Ndzisgaii — 'Valley of the Rocks' — and consider the buttes to be the dwelling places of their most sacred spiritual figures." },
{ name:"Forrest Gump Point — Highway 163", county:"San Juan, UT", emoji:"🏃", lat:36.9994, lon:-110.1219, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"The stretch of Highway 163 north of Monument Valley where <em>Forrest Gump stops his run</em> has become one of the most pilgrimaged film locations in America, with visitors recreating the iconic shot of Tom Hanks standing on the road with the Mittens buttes in the background. The location appears simple but required extensive coordination with the Navajo Nation, which controls all filming within the tribal park." },
{ name:"Goulding's Lodge — Historic Monument Valley Trading Post", county:"San Juan, UT", emoji:"🏚", lat:37.0061, lon:-110.2156, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Harry Goulding opened his trading post at Monument Valley in <em>1923</em> and in 1938 drove to Hollywood with photographs of the valley to convince John Ford to film there — a trip that launched Monument Valley's film career and transformed the remote trading post into a legend. Goulding's Lodge, still operating today, houses a museum dedicated to the films made in Monument Valley and the Navajo actors who appeared in them." },
{ name:"Navajo Nation — Four Corners Monument", county:"San Juan, UT", emoji:"🗺", lat:36.9991, lon:-109.0452, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Four Corners is the <em>only point in the United States</em> where four states — Utah, Colorado, New Mexico, and Arizona — meet at a single point, marked by a granite and brass monument administered by the Navajo Nation. The monument was first surveyed in 1868 and the current marker was installed in 1992, allowing visitors to simultaneously stand in four states." },
{ name:"Natural Bridges National Monument", county:"San Juan, UT", emoji:"🌉", lat:37.6019, lon:-110.0072, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Natural Bridges National Monument contains three of the largest natural bridges in the world — Sipapu, Kachina, and Owachomo — carved by the same ephemeral stream over <em>10,000 years</em> as it cut through white Cedar Mesa sandstone. The monument was designated in 1908 as Utah's first national monument and was the first place in the world to be powered entirely by solar energy, in 1980." },
{ name:"Bears Ears National Monument", county:"San Juan, UT", emoji:"🐻", lat:37.6258, lon:-109.8247, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Bears Ears National Monument takes its name from twin buttes that the Navajo, Hopi, Zuni, Ute, and Ute Mountain Ute peoples consider among their most sacred landscapes, and its designation in 2016 was the first time <em>tribal nations were formally co-managers</em> of a federal monument. The monument contains over 100,000 archaeological sites including cliff dwellings, petroglyphs, and ancient kivas." },
{ name:"Valley of the Gods — San Juan County", county:"San Juan, UT", emoji:"🏜", lat:37.2892, lon:-109.9500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Valley of the Gods is often called <em>'Monument Valley without the crowds'</em> — a BLM-managed landscape of isolated sandstone buttes and mesas that offer the same dramatic visuals with a fraction of the visitors. The valley's 17-mile dirt road is passable in dry weather by regular vehicles and has been used as a filming location for commercials and independent films seeking Monument Valley's aesthetic." },
{ name:"Muley Point Overlook", county:"San Juan, UT", emoji:"⛰", lat:37.2292, lon:-109.9369, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Muley Point offers what many photographers and filmmakers consider the <em>finest panoramic view in Utah</em> — a 1,000-foot cliff edge overlooking a sweeping bend of the San Juan River, the Goosenecks below, Monument Valley in the distance, and Navajo Mountain on the horizon. The overlook has been used in multiple film productions and is a pilgrimage site for landscape photographers." },
{ name:"Goosenecks State Park", county:"San Juan, UT", emoji:"🌊", lat:37.1747, lon:-109.9275, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Goosenecks of the San Juan River are one of the finest examples of <em>entrenched meanders</em> in the world — the river makes five tight bends to travel just 1.5 miles in a straight line, cutting 1,000 feet deep into the Colorado Plateau over six million years. The overlook offers a vertiginous view directly down into the canyon, and the geological formation has appeared in numerous documentary films about river systems." },
{ name:"Mexican Hat Rock Formation", county:"San Juan, UT", emoji:"🪨", lat:37.1519, lon:-109.8617, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Mexican Hat rock formation — a <em>60-foot wide sandstone disk</em> balanced on a narrow pedestal — is one of Utah's most recognizable geological formations and gave its name to the nearby town. The formation appears in the background of several shots in John Ford's Monument Valley films and has been a landmark for Navajo people navigating the canyon country for centuries." },
{ name:"San Juan River Canyon — Bluff Utah", county:"San Juan, UT", emoji:"🚣", lat:37.2831, lon:-109.5528, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The San Juan River canyon below Bluff is one of the most archaeologically rich river corridors in North America, where <em>800-year-old Ancestral Puebloan cliff dwellings</em> are visible from the river and hundreds of miles of canyon walls are covered with petroglyphs and pictographs. The river's multi-day float trips are considered among the finest wilderness experiences in the American Southwest." },
{ name:"Bluff Historic District — Utah's First Permanent Settlement", county:"San Juan, UT", emoji:"🏘", lat:37.2836, lon:-109.5497, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Bluff was settled in <em>1880 by 250 Mormon pioneers</em> who made one of the most extraordinary overland journeys in American history — cutting a road through solid sandstone at Hole-in-the-Rock to reach the San Juan River. The town's historic sandstone homes, many still occupied by descendants of the original settlers, are among the finest examples of pioneer architecture in the Four Corners region." },
{ name:"Hole-in-the-Rock Historic Trail", county:"San Juan, UT", emoji:"🛤", lat:37.2836, lon:-109.5000, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Hole-in-the-Rock was a <em>45-degree crack in a 2,000-foot cliff</em> through which Mormon pioneers blasted and chiseled a passage for their wagons in 1880, lowering them by ropes to the Colorado River below in one of the most audacious feats of pioneer engineering in American history. The trail's final descent, a near-vertical slot through solid rock, took six weeks to construct and has been the subject of several documentary films." },
{ name:"Edge of the Cedars State Park Museum", county:"San Juan, UT", emoji:"🏺", lat:37.6217, lon:-109.4783, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Edge of the Cedars State Park in Blanding preserves an <em>Ancestral Puebloan village</em> built between 825 and 1225 AD, with six room blocks and a great kiva still partially intact. The museum's collection of Ancestral Puebloan pottery is one of the finest in the Four Corners region, and its archives contain thousands of artifacts recovered from the surrounding canyon country." },
{ name:"Newspaper Rock State Historic Monument", county:"San Juan, UT", emoji:"📰", lat:37.9956, lon:-109.5203, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Newspaper Rock's single sandstone panel contains over <em>650 petroglyphs</em> created by Native Americans from multiple cultures over 2,000 years, making it one of the largest and most diverse collections of rock art on a single surface in North America. The Navajo call it Tse' Hone — 'rock that tells a story' — and the site has never been completely deciphered." },
{ name:"Canyonlands National Park — Needles District", county:"San Juan, UT", emoji:"🏜", lat:38.1525, lon:-109.8064, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Canyonlands' Needles District takes its name from the <em>colorful spires of Cedar Mesa sandstone</em> that rise hundreds of feet from the desert floor in stripes of red and white, creating a landscape so alien that it was used to train Apollo astronauts for lunar exploration. The district's 60 miles of backpacking trails pass through some of the most remote wilderness in the American Southwest." },
{ name:"Butch Cassidy's Hideout — Robbers Roost Country", county:"San Juan, UT", emoji:"🤠", lat:38.2333, lon:-110.0500, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Robbers Roost in the canyon country north of Hanksville was the primary hideout of Butch Cassidy and the Wild Bunch, who used the <em>labyrinthine canyon system</em> to evade posses for over a decade in the 1890s. The area's isolation — a 60-mile dirt road from the nearest town — means the landscape looks virtually unchanged from Cassidy's era and has been used in several Western film productions." },
{ name:"Monument Valley — Teardrop Arch", county:"San Juan, UT", emoji:"🌅", lat:36.9833, lon:-110.0833, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Teardrop Arch, accessible only on guided Navajo Nation tours within Monument Valley, frames <em>a perfect view of the Mittens buttes</em> through its teardrop-shaped opening — one of the most sought-after photographic compositions in the American Southwest. The arch is considered sacred by the Navajo people and access is deliberately controlled to preserve both the physical site and its spiritual significance." },
{ name:"Mexican Water Trading Post — Navajo Nation", county:"San Juan, UT", emoji:"🪶", lat:36.9167, lon:-109.5833, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"The remote trading posts of the Navajo Nation, including Mexican Water, have operated continuously since the <em>late 19th century</em> as commercial and cultural exchange points between Navajo weavers and the outside world. The rugs, jewelry, and pottery traded at these posts helped define the American Southwest aesthetic and made Navajo crafts among the most collected indigenous art forms in the world." },
{ name:"San Juan County Fair — Monticello Utah", county:"San Juan, UT", emoji:"🎡", lat:37.8717, lon:-109.3428, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Monticello, the county seat of San Juan County, sits at <em>7,069 feet elevation</em> making it one of the highest county seats in Utah, and its annual San Juan County Fair celebrates the ranching and farming heritage of a county that is 60% Navajo Nation land. The town's historic downtown preserves several buildings from the early 20th century when uranium and vanadium mining transformed the local economy." },

// ── San Juan County additional entries ──
{ name:"Comb Ridge — Ancient Travel Corridor", county:"San Juan, UT", emoji:"🪨", lat:37.4500, lon:-109.6500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Comb Ridge is a <em>100-mile monocline</em> — a single fold of sandstone rising 800 feet from the desert floor — that served as both a barrier and a travel corridor for the Ancestral Puebloan people, who built dozens of cliff dwellings in its alcoves. The ridge's eastern face is one of the most densely populated archaeological landscapes in the Southwest." },
{ name:"Butler Wash Ruins — Ancestral Puebloan Cliff Dwelling", county:"San Juan, UT", emoji:"🏺", lat:37.4083, lon:-109.7483, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Butler Wash Ruins, visible from a short trail above Comb Ridge, contain a well-preserved <em>four-story cliff dwelling</em> built around 1200 CE in a sandstone alcove that provided shelter and defensive position for its Ancestral Puebloan inhabitants. The site's accessibility has made it one of the most visited archaeological sites in the Bears Ears region." },
{ name:"Cedar Mesa — Grand Gulch Primitive Area", county:"San Juan, UT", emoji:"🦅", lat:37.5000, lon:-110.1500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Grand Gulch is a <em>50-mile canyon system</em> cutting through Cedar Mesa that contains the highest density of Ancestral Puebloan archaeological sites in North America — some estimates suggest over 3,000 ruins including cliff dwellings, kivas, and granaries within the canyon walls. The area was first documented by Richard Wetherill in 1893, the same man who discovered Mesa Verde." },
{ name:"Moon House — Cedar Mesa Cliff Dwelling", county:"San Juan, UT", emoji:"🌙", lat:37.5500, lon:-109.9500, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Moon House on Cedar Mesa is one of the <em>finest examples of Ancestral Puebloan architecture</em> remaining in the Southwest — a multi-room cliff dwelling built around 1200 CE with distinctive circular and crescent-shaped painted decorations that give it its name. The site requires a permit to visit, limiting access to preserve both the physical ruins and the spiritual connection the Hopi and Navajo maintain with the site." },
{ name:"Abajo Mountains — Bears Ears Buttes", county:"San Juan, UT", emoji:"🐻", lat:37.8333, lon:-109.4500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Bears Ears — twin buttes rising above the Bears Ears National Monument — are visible from <em>over 100 miles away</em> across the Colorado Plateau and serve as a sacred landmark for five tribal nations who have used them for navigation and ceremony for thousands of years. The buttes' distinctive silhouette appears in the creation stories of the Navajo, Hopi, Ute, Zuni, and Pueblo peoples." },
{ name:"Mule Canyon Ruins — Cedar Mesa", county:"San Juan, UT", emoji:"🏺", lat:37.6500, lon:-109.8000, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Mule Canyon contains an unusually complete <em>Ancestral Puebloan village complex</em> including a kiva, round tower, and connecting passageways that are in extraordinary preservation after 800 years of abandonment. The site's accessibility from a paved road has made it one of the most educational archaeological sites in the Bears Ears region." },
{ name:"Blanding — Utah's Dinosaur Museum", county:"San Juan, UT", emoji:"🦕", lat:37.6217, lon:-109.4783, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Utah's Dinosaur Museum in Blanding houses one of the finest collections of <em>dinosaur fossils excavated from San Juan County</em>, including rare specimens from the Morrison and Cedar Mountain formations that make this region one of the most productive paleontological areas in North America. The museum's collection includes a juvenile Stegosaurus discovered nearby that is among the finest such specimens ever found." },
{ name:"Recapture Canyon — Ancestral Puebloan Sites", county:"San Juan, UT", emoji:"🏺", lat:37.6000, lon:-109.5000, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Recapture Canyon near Blanding contains dozens of <em>Ancestral Puebloan sites</em> including cliff dwellings, towers, and granaries built between 800 and 1300 CE that tell the story of a sophisticated farming culture that thrived in the canyon country for centuries before mysteriously abandoning their villages. The canyon has been at the center of contentious debates about access rights between off-road vehicle users and archaeological preservation advocates." },
{ name:"Canyonlands National Park — The Maze District", county:"San Juan, UT", emoji:"🗺", lat:38.2092, lon:-110.0519, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Maze District of Canyonlands is considered the <em>most remote and difficult terrain</em> in the National Park System — a labyrinth of canyons requiring 4WD vehicles and expert navigation to reach, with no maintained trails and only one water source accessible to hikers. The district is where Christopher McCandless — the subject of the book and film Into the Wild — briefly camped during his journey to Alaska." },
{ name:"Goblin Valley Road — San Rafael Swell Gateway", county:"San Juan, UT", emoji:"👾", lat:38.5697, lon:-110.7081, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The approach to Goblin Valley through the San Rafael Swell passes a landscape of <em>eroded Entrada sandstone hoodoos</em> that inspired the alien landscape scenes in the 1999 film Galaxy Quest, where the cast literally romps among the strange formations. The valley's thousands of mushroom-shaped rock figures have been described as the most unusual landscape on Earth outside of planetary science fiction." },
{ name:"Mexican Hat — San Juan River Overlook", county:"San Juan, UT", emoji:"🌅", lat:37.1519, lon:-109.8617, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The tiny town of Mexican Hat sits at the junction of Highway 163 and the San Juan River, where the <em>Monument Valley buttes are visible</em> to the south and the Goosenecks to the west — one of the finest landscape convergences in the American Southwest. The town's trading post has served Navajo Nation residents and travelers since the 1920s." },
{ name:"Bears Ears — Shash Jaa National Monument Area", county:"San Juan, UT", emoji:"🦅", lat:37.6500, lon:-109.9000, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Navajo name for Bears Ears — Shash Jaa — refers to the twin buttes that have guided Navajo shepherds and travelers across the <em>Colorado Plateau for centuries</em>, their distinctive silhouette visible from as far as Monument Valley. The national monument established here in 2016 was the culmination of years of advocacy by tribal nations who sought federal protection for over 100,000 archaeological sites." },
{ name:"Hovensweep National Monument", county:"San Juan, UT", emoji:"🏰", lat:37.3839, lon:-109.0739, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Hovenweep's six prehistoric villages contain some of the <em>most sophisticated tower architecture</em> ever built by Ancestral Puebloan people — multi-story stone towers perched on canyon rims and boulders with precision astronomical alignments that track the solstices and equinoxes. The towers' construction around 1200 CE was so advanced that archaeologists debate whether they served as observatories, defensive fortifications, or ceremonial centers." },
{ name:"Navajo Nation — Kayenta Township", county:"San Juan, UT", emoji:"🪶", lat:36.7228, lon:-110.2564, cat:"Historic Town", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Kayenta, just south of Monument Valley on the Navajo Nation, served as the <em>base camp for John Ford's film crews</em> during the making of his Monument Valley Westerns and the Navajo actors who appeared in his films lived in the surrounding community. The town today is a gateway community where Navajo Nation governance, culture, and tourism infrastructure intersect." },
{ name:"Monument Valley — Hunt's Mesa Overlook", county:"San Juan, UT", emoji:"🌅", lat:36.9167, lon:-110.0833, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Hunt's Mesa, accessible only on guided Navajo Nation tours by 4WD vehicle, offers the <em>highest overlook in Monument Valley</em> — a 6,000-foot mesa top with a 360-degree panorama of the buttes, mesas, and canyon country stretching to the horizon in every direction. Sunrise from Hunt's Mesa is considered one of the most spectacular natural spectacles in the American Southwest." },
{ name:"Canyonlands — Confluence Overlook", county:"San Juan, UT", emoji:"🌊", lat:38.1500, lon:-109.9000, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The confluence of the Colorado and Green Rivers, visible from an overlook in Canyonlands' Island in the Sky district, is the point where <em>two of the American West's greatest rivers merge</em> 2,000 feet below the canyon rim. The two rivers flow side by side for a short distance before combining, their different colors visible in aerial photographs." },

// ═══════════════════════════════════════════════════════════
// GRAND COUNTY, UTAH — Moab & Arches Country
// ═══════════════════════════════════════════════════════════

{ name:"Arches National Park", county:"Grand, UT", emoji:"🌉", lat:38.7331, lon:-109.5925, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Arches National Park contains over <em>2,000 natural stone arches</em> — the highest concentration in the world — formed when underground salt deposits dissolved and caused the overlying sandstone to crack, erode, and ultimately form arches over millions of years. The park has appeared in Indiana Jones and the Last Crusade, Transformers, and dozens of commercials and documentaries." },
{ name:"Delicate Arch — Arches National Park", county:"Grand, UT", emoji:"🌅", lat:38.7436, lon:-109.4993, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Delicate Arch, standing <em>65 feet tall</em> in freestanding isolation above a slickrock bowl with the La Sal Mountains behind it, is the most recognized natural arch in the world and appears on Utah's license plate. The three-mile hike to reach it crosses open slickrock with no shade, making it one of the most intensely physical pilgrimages in American national park tourism." },
{ name:"Canyonlands National Park — Island in the Sky", county:"Grand, UT", emoji:"🏜", lat:38.4544, lon:-109.8203, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Island in the Sky mesa stands <em>2,000 feet above</em> the confluence of the Colorado and Green Rivers, offering one of the most commanding views in North America — a 100-mile panorama of canyon country that took NASA astronauts' breath away when they trained here for lunar missions. The district served as a filming location for Thelma and Louise's iconic final scene." },
{ name:"Thelma and Louise Point — Dead Horse Point", county:"Grand, UT", emoji:"🎬", lat:38.4828, lon:-109.7411, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Dead Horse Point State Park, where Thelma and Louise drove their Thunderbird off the edge in the <em>1991 film's iconic final shot</em>, offers a 2,000-foot sheer drop into a sweeping bend of the Colorado River that is considered one of the most dramatic viewpoints in North America. The film's cinematographer used the location's unmatched scale to create an image of freedom and finality that has become one of cinema's most enduring conclusions." },
{ name:"Moab — Film Location Capital of Utah", county:"Grand, UT", emoji:"🎬", lat:38.5733, lon:-109.5498, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab has served as a filming location for over <em>100 major productions</em> including Indiana Jones and the Last Crusade, Thelma and Louise, Mission Impossible II, Geronimo, and Gravity — making it pound for pound the most filmed small town in America. The Film Commission estimates that over $500 million in production value has been filmed in the Moab area since John Ford first used the region in the 1940s." },
{ name:"Colorado River — Moab Scenic Byway", county:"Grand, UT", emoji:"🚣", lat:38.6061, lon:-109.6200, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Highway 128 along the Colorado River north of Moab is considered <em>one of the most scenic drives in America</em>, passing through a narrow red rock canyon where the river, highway, and railroad share a corridor barely wide enough for all three. The corridor has been used in numerous car commercials and road trip films, and the Castle Rock formation along the route appeared in the opening of the TV series Westworld." },
{ name:"La Sal Mountains Overlook", county:"Grand, UT", emoji:"🏔", lat:38.5011, lon:-109.4853, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The La Sal Mountains rise to <em>12,721 feet</em> directly above the canyon country, creating one of the most dramatic elevation contrasts in North America — from the 4,000-foot desert floor to snow-capped peaks in less than 15 miles as the crow flies. The mountains' cool forests and meadows provide summer refuge for canyon country wildlife and appear as the backdrop in dozens of Arches and Canyonlands photographs." },
{ name:"Professor Valley — Castle Valley Film Location", county:"Grand, UT", emoji:"🎬", lat:38.6417, lon:-109.4333, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Castle Valley's isolated monoliths — Castleton Tower, the Rectory, and the Priest and Nuns — have appeared in <em>Westworld, Thelma and Louise, Indiana Jones,</em> and over 50 other productions as stand-ins for every kind of dramatic landscape from alien worlds to ancient civilizations. Castleton Tower, a 400-foot sandstone spire, is considered one of the premier technical rock climbing destinations in North America." },
{ name:"Moab Giants — Dinosaur Museum", county:"Grand, UT", emoji:"🦕", lat:38.5869, lon:-109.5781, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Moab area contains some of the richest <em>dinosaur fossil deposits</em> in North America, including the 150-million-year-old Morrison Formation which has produced Stegosaurus, Brachiosaurus, and Allosaurus specimens. The Moab Giants museum offers life-size dinosaur replicas in an outdoor prehistoric landscape and has been used as a filming location for dinosaur documentaries and science fiction productions." },
{ name:"Uranium Mining Heritage Site — Atlas Mill Tailings", county:"Grand, UT", emoji:"☢", lat:38.5567, lon:-109.5636, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab was the <em>uranium capital of the world</em> in the 1950s during the Cold War nuclear weapons boom, when Charlie Steen's Mi Vida uranium mine made him a multimillionaire overnight and transformed the remote ranching town into a boomtown. The Atlas Mill tailings pile — 16 million tons of radioactive waste on the banks of the Colorado River — was cleaned up in a 12-year project completed in 2019." },
{ name:"Dead Horse Point State Park", county:"Grand, UT", emoji:"🏇", lat:38.4828, lon:-109.7411, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Dead Horse Point takes its name from a <em>legendary incident</em> where cowboys used the narrow mesa neck as a natural corral, then abandoned a herd of horses that died of thirst within sight of the Colorado River 2,000 feet below. The state park's overlook is considered one of the ten most spectacular viewpoints in America and has appeared in more films and commercials than any other Utah state park." },
{ name:"Moab Valley — Hollywood Stuntman's Hall of Fame", county:"Grand, UT", emoji:"🤠", lat:38.5733, lon:-109.5498, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Hollywood Stuntman's Hall of Fame in Moab celebrates the daring professionals who have performed <em>death-defying stunts</em> in the canyon country surrounding the town, including the famous car chase scene in Indiana Jones and the Last Crusade filmed on the canyon roads above Moab. The museum's collection of stunt equipment, photographs, and memorabilia documents a century of filmmaking in the Utah canyon country." },
{ name:"Fisher Towers Recreation Area", county:"Grand, UT", emoji:"🗼", lat:38.7153, lon:-109.3128, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Fisher Towers, a cluster of ancient mud-encrusted sandstone spires rising <em>900 feet</em> from the Colorado River valley, are among the most dramatic geological formations in Utah and have been used as a filming location for commercials, car advertisements, and the opening sequence of the television series Westworld. The tallest tower, Ancient Art, has a corkscrew formation at its summit that is considered one of the most technically challenging rock climbs in North America." },
{ name:"Anticline Overlook — Behind the Rocks", county:"Grand, UT", emoji:"🏜", lat:38.4047, lon:-109.6653, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Anticline Overlook above the Colorado River canyon offers a <em>dramatic bird's-eye view</em> of a geological anticline — an upward arch of rock layers that indicates where ancient salt deposits pushed the overlying strata upward before collapsing. The overlook has appeared in several geology documentary films and the canyon below contains some of the most accessible river archaeology in the Moab area." },
{ name:"Moab Giants — Mill Canyon Dinosaur Trail", county:"Grand, UT", emoji:"🦖", lat:38.7308, lon:-109.6500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Mill Canyon's exposed Morrison Formation contains <em>actual dinosaur bones protruding from the rock</em> along a self-guided trail, where Jurassic-era Stegosaurus and sauropod remains can be seen without excavation. The site's accessibility has made it a popular filming location for dinosaur documentaries that want to show genuine fossil bones in their natural geological context." },
{ name:"Gemini Bridges Trail", county:"Grand, UT", emoji:"🌉", lat:38.6358, lon:-109.7261, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Gemini Bridges are <em>twin natural stone arches</em> accessible by a popular mountain bike and 4WD trail that offers panoramic views of Canyonlands and the La Sal Mountains — considered among the most scenic off-road routes in the American Southwest. The bridges' location on the rim of a dramatic canyon has made them a popular location for adventure sports filming and extreme cycling documentaries." },
{ name:"Colorado Riverway Recreation Area — Potash Road", county:"Grand, UT", emoji:"🚗", lat:38.4658, lon:-109.6906, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Potash Road along the Colorado River south of Moab passes a <em>remarkable sequence of ancient petroglyphs</em> carved into the canyon walls, including life-size human figures, bighorn sheep, and geometric designs spanning over 2,000 years of Native American occupation. The road ends at the Potash evaporation ponds, where blue and turquoise mineral pools contrast dramatically with the red desert landscape." },
{ name:"Moab Art Ranch — Epicenter of Utah Film Country", county:"Grand, UT", emoji:"🎨", lat:38.5733, lon:-109.5498, cat:"Arts", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab's arts community, centered around the Moab Arts and Recreation Center and several independent galleries, has grown alongside the film industry to make the town a <em>significant hub of visual culture</em> in the American West. Artists from around the world come to paint, photograph, and sculpt in the canyon country, drawn by the same extraordinary light and landscape that has attracted filmmakers for 80 years." },

// ── Grand County additional entries ──
{ name:"Arches — Landscape Arch", county:"Grand, UT", emoji:"🌉", lat:38.7908, lon:-109.6064, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Landscape Arch, with a span of <em>290 feet</em>, is the longest natural arch in the world — a ribbon of sandstone so thin at its center that geologists predict it could collapse at any time. Three large slabs fell from its underside in 1991, and the trail was rerouted as a precaution; visitors now watch from a distance as the arch slowly thins." },
{ name:"Colorado Riverway — Morning Glory Bridge", county:"Grand, UT", emoji:"🌄", lat:38.6200, lon:-109.5400, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Morning Glory Natural Bridge, accessible by a 5-mile round-trip hike from the Moab Valley, has a <em>243-foot span</em> and frames a swimming pool fed by a perennial spring in the canyon below. The arch's graceful curve and the turquoise pool beneath it have made it one of the most photographed natural features in the Moab area." },
{ name:"Moab Giants Tracksite", county:"Grand, UT", emoji:"🦶", lat:38.6600, lon:-109.6800, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Moab Giants dinosaur tracksite preserves over <em>200 dinosaur footprints</em> from at least five species embedded in Jurassic-era mudstone, including the three-toed tracks of large therapod dinosaurs that stalked this ancient riverbank 150 million years ago. The tracksite's accessibility and scientific significance have made it one of the most visited paleontological sites in Utah." },
{ name:"Colorado River Scenic Byway — Highway 128", county:"Grand, UT", emoji:"🚗", lat:38.7000, lon:-109.4800, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Highway 128 along the Colorado River is one of the <em>most filmed stretches of road in America</em>, passing through a narrow red rock canyon where towering cliffs, a working railroad, and the river compete for space in a corridor barely wide enough for all three. The road's dramatic scenery has been used in dozens of automobile commercials and the opening credits of the HBO series Westworld." },
{ name:"Moab Giants — Copper Ridge Sauropod Trackway", county:"Grand, UT", emoji:"🦕", lat:38.7597, lon:-109.7153, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Copper Ridge Sauropod Trackway contains parallel tracks of a large <em>brontosaurus-type dinosaur</em> and a carnivorous therapod walking in the same direction across an ancient mudflat, preserved in stone for 150 million years. The tracks' side-by-side preservation has led paleontologists to speculate whether the carnivore was stalking the herbivore." },
{ name:"Gemini Bridges — Grand County", county:"Grand, UT", emoji:"🌉", lat:38.6300, lon:-109.7300, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Gemini Bridges are twin natural arches spanning a dramatic canyon that can be accessed by mountain bike, ATV, or on foot — offering what many consider the <em>finest view of Canyonlands</em> from any non-motorized trail in the region. The bridges' accessible location has made them one of the most popular filming locations for mountain biking and adventure sports productions." },
{ name:"Moab — Scott M. Matheson Wetlands Preserve", county:"Grand, UT", emoji:"🦆", lat:38.5658, lon:-109.5781, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Scott Matheson Wetlands Preserve is one of the most unexpected natural landscapes in the canyon country — a <em>900-acre cottonwood and tamarisk wetland</em> along the Colorado River in the heart of the Moab Valley, supporting over 200 species of birds and providing habitat for beavers, river otters, and mule deer within walking distance of downtown Moab. The preserve was named for a Utah governor who championed its conservation." },
{ name:"Moab — Behind the Rocks Wilderness Study Area", county:"Grand, UT", emoji:"🏜", lat:38.4500, lon:-109.5200, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Behind the Rocks is a <em>12,635-acre maze of Navajo sandstone fins</em> rising up to 500 feet directly south of Moab, creating one of the most disorienting and beautiful labyrinths in the American Southwest. The area served as a filming location for Mission Impossible II, where Tom Cruise's rock climbing scenes were filmed on the sheer sandstone faces." },
{ name:"Arches — Windows Section", county:"Grand, UT", emoji:"🌅", lat:38.6886, lon:-109.5386, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Windows Section of Arches National Park concentrates four large arches — North Window, South Window, Turret Arch, and Double Arch — within a <em>half-mile loop trail</em>, making it one of the most arch-dense areas on Earth accessible on a paved road. The section has been used as an establishing shot in dozens of productions and the view through the North and South Windows framing the La Sal Mountains is one of the most photographed landscape compositions in Utah." },
{ name:"Canyonlands — White Rim Road", county:"Grand, UT", emoji:"🚗", lat:38.4000, lon:-109.8000, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The White Rim Road is a <em>100-mile 4WD route</em> circling the Island in the Sky mesa of Canyonlands, running along a white sandstone bench 1,200 feet below the rim and 1,000 feet above the Colorado and Green Rivers. The multi-day jeep or mountain bike circuit offers unmatched views of canyon country and has been used in adventure film productions and extreme sports documentaries." },
{ name:"Moab — Uranium Boom Town Historic District", county:"Grand, UT", emoji:"☢", lat:38.5733, lon:-109.5498, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab's Main Street preserves several buildings from the <em>uranium boom of the 1950s</em> when the town exploded from a sleepy ranching community of 1,200 to a booming city of 6,000 virtually overnight after Charlie Steen's Mi Vida mine discovery. The Grand County Courthouse, built in 1940, and several downtown commercial blocks survive from this era and are listed on the National Register of Historic Places." },
{ name:"Canyon Rims Recreation Area", county:"Grand, UT", emoji:"🏜", lat:38.2500, lon:-109.7000, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Canyon Rims Recreation Area offers <em>rim drives with panoramic views</em> rivaling Dead Horse Point and Canyonlands but with a fraction of the visitors, making it one of the best-kept secrets in the Moab area. The Needles Overlook provides a bird's-eye view of the entire Needles district of Canyonlands 20 miles away across a sea of canyon country." },
{ name:"La Sal Mountains — Mount Peale Summit", county:"Grand, UT", emoji:"🏔", lat:38.4378, lon:-109.2283, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Mount Peale, at <em>12,721 feet</em> the highest point in the La Sal Mountains and in San Juan County, is a laccolith — a dome of igneous rock that intruded into sedimentary layers without erupting. The mountain's dramatic rise above the canyon country creates a rain shadow that contributes to the desert environment below and summit views encompass an area the size of New England." },
{ name:"Moab Valley — Rill Sites Petroglyphs", county:"Grand, UT", emoji:"🪨", lat:38.5900, lon:-109.5600, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Moab Valley contains over <em>2,000 individual petroglyph panels</em> created by Fremont and Ancestral Puebloan peoples between 500 and 1300 CE, including the famous 'Birthing Scene' and life-size anthropomorphic figures that have been interpreted as shamanic figures or supernatural beings. The panels are accessible along a paved bike path and represent one of the most visited Native American rock art sites in America." },

// ═══════════════════════════════════════════════════════════
// KANE COUNTY, UTAH — Little Hollywood & Zion Country
// ═══════════════════════════════════════════════════════════

{ name:"Kanab — Little Hollywood", county:"Kane, UT", emoji:"🎬", lat:37.0475, lon:-112.5263, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Kanab earned the nickname 'Little Hollywood' by hosting over <em>100 major Western film productions</em> between 1924 and the 1970s, including How the West Was Won, The Outlaw Josey Wales, Planet of the Apes, Maverick, and hundreds of TV episodes of Gunsmoke, The Lone Ranger, and Have Gun Will Travel. The town's red rock landscape and proximity to multiple national parks made it the preferred location for productions needing authentic Western scenery." },
{ name:"Kanab Heritage House — Old Parry Lodge", county:"Kane, UT", emoji:"🏨", lat:37.0475, lon:-112.5263, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Parry Lodge in Kanab, built in <em>1931</em> by Chauncey Parry to house film crews working in the area, hosted virtually every major Western star of Hollywood's golden era — John Wayne, Clint Eastwood, Gregory Peck, Ronald Reagan, and Frank Sinatra all stayed in its rooms. Each guest room bears the name of a star who slept there and the lobby walls are covered with autographed photos from a century of filmmaking." },
{ name:"Zion National Park — Canyon Entrance", county:"Kane, UT", emoji:"🏔", lat:37.2982, lon:-113.0263, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Zion Canyon's <em>2,000-foot vertical walls of Navajo sandstone</em> contain some of the most dramatic narrow slot canyon hiking in the world, and the park has been a filming location for Butch Cassidy and the Sundance Kid, 127 Hours, and numerous nature documentaries. The canyon's name comes from the Hebrew word for sanctuary, given by Mormon pioneer Isaac Behunin who built a cabin here in 1863 and called it his Zion." },
{ name:"The Zion Narrows", county:"Kane, UT", emoji:"🌊", lat:37.3622, lon:-112.9472, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Zion Narrows is a 16-mile canyon hike through the Virgin River where the canyon walls are as little as <em>20 feet apart</em> and 1,000 feet tall, requiring hikers to wade through the river for much of the route. The Narrows is consistently ranked as one of the top ten hikes in America and has appeared in numerous outdoor adventure films and documentaries." },
{ name:"Coral Pink Sand Dunes State Park", county:"Kane, UT", emoji:"🏜", lat:37.0344, lon:-112.7353, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Coral Pink Sand Dunes gets its distinctive <em>pink-orange color</em> from the eroded Navajo sandstone of the surrounding cliffs, which produces iron oxide-rich sand unlike any other dune field in America. The dunes have been used as a filming location for desert planet scenes in science fiction productions and the unique color has made them one of the most distinctive landscapes in Utah." },
{ name:"Bryce Canyon National Park", county:"Kane, UT", emoji:"🏔", lat:37.5930, lon:-112.1871, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"Bryce Canyon's <em>37 million hoodoos</em> — orange-pink limestone spires carved by frost and water — create one of the most surreal landscapes in North America, which the Paiute people called 'Legend People' because the formations resembled humans turned to stone. The park has appeared in dozens of films and was the inspiration for the alien landscape design in the original Star Wars cantina scene." },
{ name:"Grand Staircase-Escalante National Monument", county:"Kane, UT", emoji:"🪜", lat:37.5317, lon:-111.6942, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Grand Staircase-Escalante, designated in <em>1996</em> as America's largest national monument at 1.9 million acres, contains one of the most significant dinosaur fossil beds ever discovered — including a new species of horned dinosaur found in 2010. The monument's slot canyons, including Coyote Gulch and Peek-a-Boo Canyon, have become among the most photographed geological features in the American Southwest." },
{ name:"Escalante Petrified Forest State Park", county:"Kane, UT", emoji:"🌲", lat:37.7661, lon:-111.6111, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Escalante's petrified forest contains <em>225-million-year-old Triassic-era trees</em> turned to rainbow-colored stone, including specimens up to 9 feet in diameter that were growing when dinosaurs first appeared on Earth. The state park's wide reservoir and dramatic canyon setting have made it a popular location for landscape photography and outdoor film productions." },
{ name:"Slot Canyon — Peek-a-Boo Gulch", county:"Kane, UT", emoji:"🌈", lat:37.6456, lon:-111.7242, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Peek-a-Boo Gulch is one of the most beautifully colored slot canyons in Utah, where <em>light filters through narrow openings</em> to illuminate pink and orange walls worn smooth by ancient floods into flowing sculptural forms. The canyon has been used in numerous photography workshops, film productions, and music videos seeking a visual metaphor for mystery and beauty." },
{ name:"Moqui Cave Museum — Kanab", county:"Kane, UT", emoji:"🦕", lat:37.0814, lon:-112.5122, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Moqui Cave, a natural sandstone cave occupied by the Ancestral Puebloan people centuries ago, now houses a collection of <em>dinosaur fossils, fluorescent minerals, and Native American artifacts</em> that has been open to the public since 1951. The cave was converted into a dance hall and tavern in the 1940s by a local entrepreneur who later donated it to preservation, making it one of Utah's most unusual museums." },
{ name:"Coyote Buttes — The Wave", county:"Kane, UT", emoji:"🌊", lat:36.9958, lon:-112.0061, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Wave is a <em>swirling Navajo sandstone formation</em> whose flowing curves and vibrant colors are the result of ancient sand dune layers being compressed, tilted, and eroded over 190 million years into one of the most photographed geological features in the world. Access is strictly limited to 20 people per day by lottery, making it one of the most sought-after hiking permits in the United States." },
{ name:"Johnson Canyon — Film Set and Gunsmoke Town", county:"Kane, UT", emoji:"🎬", lat:37.1000, lon:-112.3500, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Johnson Canyon outside Kanab was where a <em>permanent Western town set</em> was built in the 1960s for the television series Gunsmoke and used continuously for decades of Western productions. The abandoned set's weathered facades, corrals, and jail remain in the canyon and are freely accessible, making it one of the most authentic ghost town film sets in the American West." },
{ name:"Pink Cliffs — Grand Staircase Rim", county:"Kane, UT", emoji:"🏔", lat:37.6539, lon:-112.3106, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"The Pink Cliffs form the <em>top step of the Grand Staircase</em> — a sequence of colorful rock layers that descend from Bryce Canyon to the Grand Canyon, representing 600 million years of geological history compressed into a single visible landscape. The cliffs' rosy hue comes from iron oxide in the limestone and the layer is the same rock formation that creates Bryce Canyon's famous hoodoos." },
{ name:"Paria Canyon — Vermilion Cliffs Wilderness", county:"Kane, UT", emoji:"🌅", lat:37.1058, lon:-111.9203, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Paria Canyon's <em>38-mile wilderness route</em> through Vermilion Cliffs is considered one of the premier canyon hiking experiences in North America, passing through slot canyons, fossil sites, and the site of the 1880s ghost town of Pahreah, which was used as a Western film location before flooding destroyed it. The canyon's walls display 200 million years of geological history in exposed rock strata." },
{ name:"Antelope Canyon — Lake Powell Overflow", county:"Kane, UT", emoji:"🌊", lat:37.1047, lon:-111.7567, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The upper reaches of Antelope Canyon, one of the most photographed slot canyons in the world, extend into Kane County where <em>light beams pierce the narrow opening</em> to illuminate swirling sandstone walls in shades of orange, red, and purple. The canyon is on Navajo Nation land and guided tours are required, limiting access in a way that has made photographs of the light beams among the most commercially valuable landscape images ever taken." },
{ name:"Kanab Creek Wilderness", county:"Kane, UT", emoji:"🦅", lat:36.8833, lon:-112.4667, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Kanab Creek flows north through a <em>dramatic 1,000-foot canyon</em> to join the Colorado River in the Grand Canyon, passing through wilderness that has remained roadless since the first European contact and supports populations of California condors reintroduced to the region in 1996. The creek corridor is one of the most biologically diverse areas of the Colorado Plateau, where desert and riparian ecosystems intersect." },
{ name:"Orderville — Historic United Order Town", county:"Kane, UT", emoji:"🏘", lat:37.2725, lon:-112.6378, cat:"Historic Town", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Orderville was founded in <em>1875</em> as a communal religious community where members of the LDS United Order shared all property equally, eating together in a common dining hall and wearing identical clothing made in a community workshop. The experiment lasted 10 years before economic pressures and human nature dissolved the commune, but Orderville remains one of the most complete surviving examples of 19th-century American utopian architecture." },
{ name:"Lake Powell — Glen Canyon Dam", county:"Kane, UT", emoji:"💧", lat:36.9369, lon:-111.4839, cat:"Historic Infrastructure", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Glen Canyon Dam, completed in <em>1966</em>, created Lake Powell by flooding Glen Canyon — which John Muir had called the most beautiful canyon in America — and displaced the Navajo and Ute communities who had lived along the Colorado River for generations. As drought has dramatically lowered the lake's level in recent years, the drowned canyon's red rock walls and archaeological sites have begun to re-emerge from the water." },
{ name:"Wahweap Marina — Lake Powell", county:"Kane, UT", emoji:"⛵", lat:36.9992, lon:-111.4894, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Wahweap Marina on Lake Powell was for decades the <em>busiest houseboat marina in the United States</em>, attracting 3 million visitors annually to cruise the labyrinthine canyon arms of the reservoir. The marina's dramatic setting beneath red rock cliffs served as a filming location for Planet of the Apes and several other science fiction productions that used the alien-looking canyon walls as stand-ins for other worlds." },
{ name:"Rainbow Bridge National Monument", county:"Kane, UT", emoji:"🌈", lat:37.0778, lon:-110.9631, cat:"National Monument", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Rainbow Bridge, at <em>290 feet tall and 275 feet wide</em>, is the largest known natural bridge in the world — so large that the U.S. Capitol Building could fit beneath its span. The Navajo, Hopi, San Juan Paiute, and Ute Mountain Ute peoples consider Rainbow Bridge a sacred site, and reaching it requires either a 14-mile hike through Navajo Nation land or a boat trip across Lake Powell." },
{ name:"Skutumpah Road — Historic Paria Film Country", county:"Kane, UT", emoji:"🛤", lat:37.3500, lon:-112.3500, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Skutumpah Road through the Grand Staircase passes the site of <em>Old Pahreah ghost town</em>, a 19th-century settlement used as a Western film location in the 1960s before it was destroyed by flooding, leaving only a cemetery and foundation stones. The road's dramatic passage through pink and white canyon country has been used in numerous automobile commercials and landscape documentaries." },
{ name:"Zion — Angels Landing Trail", county:"Kane, UT", emoji:"👼", lat:37.2690, lon:-112.9481, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Angels Landing is consistently ranked as one of the <em>ten most spectacular hikes in America</em>, culminating in a half-mile ridge walk with 1,500-foot drop-offs on both sides that requires holding chain handrails bolted into the rock. The trail has appeared in numerous adventure films and documentaries as the definitive example of Utah's extreme landscape hiking." },
{ name:"Zion — Emerald Pools Trail", county:"Kane, UT", emoji:"💚", lat:37.2558, lon:-112.9611, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Emerald Pools in Zion Canyon were formed by <em>weeping springs</em> seeping through canyon walls and falling in curtains to create hanging gardens of columbine and maidenhair fern in an otherwise desert environment. The pools have appeared in dozens of nature documentaries as examples of the biological diversity hidden within Utah's canyon country." },
{ name:"Zion — Kolob Canyons Section", county:"Kane, UT", emoji:"🏔", lat:37.4381, lon:-113.2119, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Kolob Canyons section of Zion National Park contains Kolob Arch, which at <em>287 feet</em> rivals Rainbow Bridge as one of the world's largest natural arches — yet sees only a fraction of visitors because it requires a 14-mile round-trip hike. The section's dramatic finger canyons are considered by many photographers to be even more beautiful than the main Zion Canyon." },
{ name:"Paria Townsite — Western Film Ghost Town", county:"Kane, UT", emoji:"🎬", lat:37.1058, lon:-111.9203, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Old Pahreah served as the <em>primary Western town film set in Kane County</em> for productions including Sergeants 3 and several Clint Eastwood Westerns before the Colorado River permanently destroyed the settlement in 1999. The site's cemetery, with graves dating to the 1870s, still stands above the flood line." },
{ name:"Kodachrome Basin State Park", county:"Kane, UT", emoji:"📷", lat:37.5228, lon:-111.9989, cat:"State Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"Kodachrome Basin was named by the <em>National Geographic Society in 1949</em> when photographers were so struck by its vivid colors that they named it after Kodak's color film. The park's 67 sandstone spires — unique geological features called 'sand pipes' found nowhere else on Earth — were formed when ancient geysers filled with sediment and hardened while the surrounding rock eroded away." },
{ name:"Bryce Canyon — Thor's Hammer", county:"Kane, UT", emoji:"🔨", lat:37.6308, lon:-112.1667, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"Thor's Hammer is the most recognized hoodoo in Bryce Canyon — a <em>perfectly balanced square-capped spire</em> that appears in more Bryce Canyon photographs than any other formation and seems to defy gravity as it narrows at its base. The Paiute people called formations like Thor's Hammer 'Legend People' — humans and animals turned to stone by the god Coyote." },
{ name:"Grand Staircase — Escalante River Canyons", county:"Kane, UT", emoji:"🌊", lat:37.7600, lon:-111.5800, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Escalante River and its tributaries have carved a <em>network of slot canyons</em> including Coyote Gulch, Death Hollow, and the Gulch — considered collectively as the finest slot canyon backpacking terrain in North America. The canyons' swirling sandstone walls, natural bridges, and spring-fed streams create a hidden paradise that rewards the multi-day effort required to reach them." },
{ name:"Calf Creek Falls Recreation Area", county:"Kane, UT", emoji:"💦", lat:37.7917, lon:-111.4192, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Lower Calf Creek Falls plunges <em>126 feet</em> into a pool of crystalline water in a hanging garden canyon that feels completely out of place in the surrounding sandstone desert. The 6-mile round-trip trail to the falls passes prehistoric Fremont granaries and petroglyphs, making it one of the most culturally rich short hikes in Grand Staircase-Escalante." },
{ name:"Johnson Canyon — Gunsmoke Film Set", county:"Kane, UT", emoji:"🎬", lat:37.1000, lon:-112.3500, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Johnson Canyon outside Kanab was where a <em>permanent Western town set</em> was built in the 1960s for television series including Gunsmoke and used continuously for decades of Western productions. The abandoned set's weathered facades, corrals, and jail remain freely accessible in the canyon, making it one of the most authentic ghost town film sets in the American West." },
{ name:"Kanab — Best Friends Animal Sanctuary", county:"Kane, UT", emoji:"🐕", lat:37.1833, lon:-112.5167, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Best Friends Animal Sanctuary, the largest no-kill animal sanctuary in America with over <em>1,600 animals in residence</em>, occupies a spectacular red rock canyon outside Kanab and has transformed the town into a global destination for animal welfare advocates. The sanctuary's founding in 1984 helped launch the no-kill shelter movement that has since saved millions of animals across America." },
{ name:"Alstrom Point — Lake Powell Overlook", county:"Kane, UT", emoji:"🌅", lat:37.1000, lon:-111.5500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Alstrom Point is a <em>remote promontory</em> accessible only by long dirt road that offers perhaps the finest aerial view of Lake Powell's maze of canyon arms — the flooded Glen Canyon that John Muir called the most beautiful canyon in America before it was drowned in 1966. As water levels drop due to drought, the original canyon's red rock walls re-emerge from the water in a haunting reverse of the original flooding." },
{ name:"Pipe Spring National Monument", county:"Kane, UT", emoji:"💧", lat:36.8625, lon:-112.7394, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Pipe Spring, a <em>reliable desert water source</em> used by the Kaibab Paiute for millennia, was fortified by Brigham Young in 1870 into a stone ranch known as Winsor Castle — the only significant water source for miles in any direction. The monument preserves the history of both the Paiute people and the Mormon settlers who competed for this critical resource." },
{ name:"Escalante — Historic Pioneer Town", county:"Kane, UT", emoji:"🏘", lat:37.7661, lon:-111.6011, cat:"Historic Town", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Escalante, founded in <em>1876</em> by Mormon pioneers, was the last town in the contiguous United States to be reached by a road — the gravel highway connecting it to the outside world wasn't completed until 1940. The town's isolation has preserved its 19th-century character and its position at the gateway to Grand Staircase-Escalante has made it a base camp for some of the most serious canyon country exploration in America." },
{ name:"Bryce Canyon — Sunrise Point Amphitheater", county:"Kane, UT", emoji:"🌄", lat:37.6428, lon:-112.1656, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"Sunrise Point offers the classic view of Bryce Canyon's main amphitheater — a <em>2,000-foot deep bowl containing millions of hoodoos</em> in shades of orange, red, white, and pink that change dramatically as the light shifts throughout the day. Photographers consider the hour after sunrise the optimal time to shoot the amphitheater, when low-angle light casts long shadows that emphasize the hoodoos' sculptural forms." },
{ name:"Zion — Checkerboard Mesa", county:"Kane, UT", emoji:"🏜", lat:37.2150, lon:-112.8717, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Checkerboard Mesa's crosshatched surface — created by <em>vertical fractures intersecting horizontal bedding planes</em> — is one of the most geometrically perfect natural patterns in North America and has been used in architecture and design as an example of nature's mathematical precision. The mesa marks the transition from Zion's verdant canyon interior to the high desert plateau of its eastern section." },
{ name:"Glen Canyon — Hole-in-the-Rock Road", county:"Kane, UT", emoji:"🛤", lat:37.1333, lon:-111.2667, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The 57-mile Hole-in-the-Rock Road across the Grand Staircase follows the exact route of the <em>1880 Mormon pioneer expedition</em> that blasted a passage through solid sandstone cliffs to reach the San Juan River. The road passes through some of the most remote and geologically varied terrain in Utah, with no services and no paved sections." },
{ name:"Moqui Cave Museum — Kanab", county:"Kane, UT", emoji:"🦕", lat:37.0814, lon:-112.5122, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Moqui Cave, a natural sandstone cave occupied by the Ancestral Puebloan people centuries ago, now houses a collection of <em>dinosaur fossils, fluorescent minerals, and Native American artifacts</em> open to the public since 1951. The cave was converted into a dance hall and tavern in the 1940s before being donated to preservation — one of Utah's most unusual museums." },
{ name:"The Wave — Coyote Buttes North", county:"Kane, UT", emoji:"🌊", lat:36.9958, lon:-112.0061, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Wave is a <em>swirling Navajo sandstone formation</em> whose flowing curves and vibrant colors are the result of ancient sand dune layers compressed, tilted, and eroded over 190 million years into one of the most photographed geological features in the world. Access is strictly limited to 20 people per day by lottery, making it one of the most sought-after hiking permits in the United States." },

// ── Clark County final top-up ──
{ name:"Las Vegas — The Hangover Film Locations Tour", county:"Clark, NV", emoji:"🎬", lat:36.1210, lon:-115.1696, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b9/The_Venetian_Las_Vegas.jpg/320px-The_Venetian_Las_Vegas.jpg", fact:"The Hangover trilogy filmed extensively throughout Las Vegas, using <em>Caesars Palace, the Riviera, and the roof of The Opulent Hotel</em> to capture the city's capacity for spectacular debauchery. The first film's success made Las Vegas the most commercially filmed American city of the 2010s, spawning dozens of imitators and firmly establishing the city as Hollywood's preferred backdrop for adult misadventure." },
{ name:"Titanic The Exhibition — Luxor Las Vegas", county:"Clark, NV", emoji:"🚢", lat:36.0953, lon:-115.1762, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Luxor_Las_Vegas.jpg/320px-Luxor_Las_Vegas.jpg", fact:"The Titanic Exhibition at the Luxor displays over <em>300 authentic artifacts</em> recovered from the ocean floor, including a 15-ton section of the ship's hull — one of the most dramatic museum artifacts on permanent display anywhere in the world. The exhibition receives over 4 million visitors annually, making it one of the most attended non-casino attractions in Las Vegas." },
{ name:"Las Vegas — Circa Resort Circa Stadium Swim", county:"Clark, NV", emoji:"🏊", lat:36.1694, lon:-115.1378, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Fremont_Street_Experience.jpg/320px-Fremont_Street_Experience.jpg", fact:"Circa Resort's Stadium Swim is the <em>largest pool amphitheater in the world</em> — a six-pool complex with a 40-foot screen showing sports events while guests swim, creating one of Las Vegas's most surreal recreational experiences. The complex holds 4,000 guests and its opening in 2020 during the COVID pandemic demonstrated Las Vegas's determination to create new spectacles even in adversity." },
{ name:"Las Vegas — The High Roller Observation Wheel", county:"Clark, NV", emoji:"🎡", lat:36.1175, lon:-115.1642, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Caesars_Palace_Las_Vegas.jpg/320px-Caesars_Palace_Las_Vegas.jpg", fact:"The High Roller at the LINQ is the <em>tallest observation wheel in the world</em> at 550 feet, with 28 glass cabins each holding up to 40 people on a 30-minute rotation above the Las Vegas Strip. The wheel's prime location at the center of the Strip has made it a landmark visible in virtually every aerial photograph of Las Vegas taken since its opening in 2014." },
{ name:"Las Vegas — AREA15 Immersive Art District", county:"Clark, NV", emoji:"🎨", lat:36.1356, lon:-115.1858, cat:"Arts", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Neon_Museum_Las_Vegas.jpg/320px-Neon_Museum_Las_Vegas.jpg", fact:"AREA15 is Las Vegas's first permanent immersive art and entertainment complex, a <em>200,000-square-foot warehouse district</em> housing over 40 immersive experiences including Meow Wolf's Omega Mart, which has been called the most ambitious immersive art installation in American history. The complex represents Las Vegas's evolution from gambling entertainment to experience-based culture." },
{ name:"Henderson — Ethel M Cactus Garden Christmas", county:"Clark, NV", emoji:"🎄", lat:36.0467, lon:-115.0411, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Every December, the Ethel M Cactus Garden in Henderson is transformed into one of Nevada's <em>most beloved holiday traditions</em> when over a million lights illuminate 350 species of cacti and succulents in a spectacle that perfectly captures Las Vegas's capacity for theatrical excess. The free holiday display attracts over 100,000 visitors in December alone." },
{ name:"Las Vegas — T-Mobile Arena and Golden Knights", county:"Clark, NV", emoji:"🏒", lat:36.1028, lon:-115.1783, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Caesars_Palace_Las_Vegas.jpg/320px-Caesars_Palace_Las_Vegas.jpg", fact:"T-Mobile Arena, which opened in 2016, became home to the Vegas Golden Knights — the first major professional sports franchise in Las Vegas — who in their <em>first season reached the Stanley Cup Finals</em> in the most successful expansion team debut in NHL history. The arena's opening transformed Las Vegas from an entertainment city into a legitimate major-league sports market." },
{ name:"Las Vegas — Raiders Allegiant Stadium", county:"Clark, NV", emoji:"🏈", lat:36.0909, lon:-115.1833, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Luxor_Las_Vegas.jpg/320px-Luxor_Las_Vegas.jpg", fact:"Allegiant Stadium, the $1.9 billion home of the Las Vegas Raiders, is one of the most technologically advanced sports venues ever built — a <em>dark glass dome</em> with a retractable natural grass field that rolls in and out and a 93-foot tall Al Davis Memorial Torch burning at the south end. The stadium hosted Super Bowl LVIII in 2024, cementing Las Vegas's arrival as a premier destination for major sporting events." },
{ name:"Las Vegas — Resorts World and East Strip Development", county:"Clark, NV", emoji:"🎰", lat:36.1300, lon:-115.1650, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Las_Vegas_Strip_at_night%2C_January_2016.jpg/320px-Las_Vegas_Strip_at_night%2C_January_2016.jpg", fact:"Resorts World Las Vegas, opened in 2021, is the first <em>new resort built on the Strip</em> in over a decade and the largest hotel in the United States, with 3,500 rooms in three interconnected towers. Its opening marked a new chapter in Las Vegas's development, combining traditional casino gambling with food halls, concert venues, and technology-enhanced experiences aimed at younger visitors." },

// ── Mohave County final top-up ──
{ name:"Laughlin — Don Laughlin's Riverside Resort", county:"Mohave, AZ", emoji:"🎰", lat:35.1683, lon:-114.5747, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"Don Laughlin's Riverside Resort, built from a single bait shop purchased for <em>$250 in 1966</em>, grew into the anchor of a casino district on the Colorado River that now attracts 3 million visitors annually. Don Laughlin, who literally built the town of Laughlin with his own hands, is one of the last self-made casino pioneers in Nevada — a true rags-to-riches story in the tradition of the American West." },
{ name:"Kingman — Historic Downtown Beale Street", county:"Mohave, AZ", emoji:"🏘", lat:35.1894, lon:-114.0530, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's Beale Street historic district preserves the commercial heart of a railroad and Route 66 town that has served travelers crossing the Mojave Desert since <em>1882</em>, when the Atlantic and Pacific Railroad arrived. The street's brick commercial buildings, several dating to the early 1900s, house antique shops, diners, and Route 66 memorabilia stores that make Kingman one of the most authentic stops on the Mother Road." },
{ name:"Lake Havasu — Spring Break Capital of the West", county:"Mohave, AZ", emoji:"🎉", lat:34.4839, lon:-114.3286, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Lake Havasu City became one of America's premier spring break destinations in the 1980s and 1990s, when its warm weather, accessible lake, and proximity to college campuses in Arizona and California attracted <em>tens of thousands of students</em> annually. The spring break culture that developed here was the subject of several documentary films and reality television shows that shaped popular perceptions of American college culture." },
{ name:"Mohave County — Bill Williams Mountain", county:"Mohave, AZ", emoji:"🏔", lat:35.2528, lon:-112.1917, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Bill Williams Mountain, rising to <em>9,256 feet</em> above the Colorado Plateau near Williams, Arizona, is named for mountain man Bill Williams — one of the most legendary figures of the American frontier whose encyclopedic knowledge of the Southwest saved dozens of explorers' lives. The mountain's forests transition from desert scrub at the base to spruce-fir at the summit, supporting one of the most diverse plant communities in Arizona." },
{ name:"Arizona Strip — Isolated Wilderness Region", county:"Mohave, AZ", emoji:"🌵", lat:36.5000, lon:-113.5000, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Arizona Strip — the 12,000-square-mile area between the Grand Canyon's North Rim and the Utah state line — is the most isolated region in the contiguous United States, with <em>fewer than 4,000 permanent residents</em> in an area larger than the states of Connecticut and Rhode Island combined. The Strip's isolation preserved its ranching culture and landscape virtually unchanged through the 20th century." },
{ name:"Willow Beach — Colorado River Below Hoover Dam", county:"Mohave, AZ", emoji:"🎣", lat:35.8597, lon:-114.6561, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Colorado River below Hoover Dam maintains a constant <em>55°F temperature year-round</em> from the cold water released through the dam's turbines, creating one of the finest trout fisheries in the Southwest in the middle of the Mojave Desert. The 12-mile stretch to Willow Beach is accessible only by boat or kayak, offering one of the most pristine river experiences remaining in the Colorado River system." },
{ name:"Kingman — Andy Devine Avenue Historic Route 66", county:"Mohave, AZ", emoji:"🛤", lat:35.1894, lon:-114.0530, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's main Route 66 corridor is named Andy Devine Avenue after the hometown character actor who appeared in <em>over 400 films and television episodes</em>, most memorably as the driver Cully in John Ford's Stagecoach. The street's collection of vintage motels, neon signs, and drive-in restaurants preserves the visual culture of mid-20th century American road travel." },
{ name:"Mohave Desert — Joshua Tree National Area", county:"Mohave, AZ", emoji:"🌵", lat:34.9000, lon:-114.2000, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Mohave Desert of northwestern Arizona contains some of the <em>densest Joshua tree forests</em> outside of California, where the slow-growing succulents — capable of living 500 years — create cathedral-like groves on the high desert benches above the Colorado River. The Joshua tree's range is entirely within the Mojave Desert and its presence is the primary indicator of the Mojave ecosystem." },
{ name:"Cerbat Mountains Wilderness", county:"Mohave, AZ", emoji:"🦅", lat:35.4000, lon:-114.2500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Cerbat Mountains north of Kingman are one of the most geologically diverse ranges in Arizona, containing rocks spanning <em>1.7 billion years of Earth history</em> from Precambrian basement to recent volcanic flows. The mountains' mineral wealth attracted miners from the 1860s onward, and the abandoned silver and turquoise mines that honeycomb the range are now home to one of Arizona's largest bat colonies." },
{ name:"Lake Havasu — Havasu Landing Resort", county:"Mohave, AZ", emoji:"🚤", lat:34.5317, lon:-114.3983, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Havasu Landing on the California side of Lake Havasu is operated by the Chemehuevi Indian Tribe, whose reservation encompasses the <em>western shore of the lake</em> — a unique situation where tribal sovereignty and state jurisdiction meet at the water's edge. The resort's casino, hotel, and marina are operated entirely by tribal members and represent one of the most successful tribal gaming enterprises in the lower Colorado River region." },
{ name:"Oatman Highway — Historic Gold Road", county:"Mohave, AZ", emoji:"⛰", lat:34.8600, lon:-114.3900, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Oatman Highway between Kingman and Needles is the most <em>dramatic surviving stretch of original Route 66</em>, a two-lane road that climbs through the Black Mountains on hairpin turns with sheer drop-offs that terrified Depression-era drivers in overloaded cars. The road's extreme grade — up to 15% — made it the most feared section of the Mother Road and the last place many Dust Bowl migrants saw before leaving the desert behind." },
{ name:"Kingman — Locomotive Park", county:"Mohave, AZ", emoji:"🚂", lat:35.1894, lon:-114.0611, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's Locomotive Park preserves a <em>1928 steam locomotive</em> and several historic railroad cars from the Atchison, Topeka and Santa Fe Railway that built the town, displayed beside Beale Street as a monument to the railroad era that created modern Kingman. The park's locomotive is the same class of engine that pulled passenger trains across the Mojave Desert on the route that became Route 66." },

// ── San Juan County final top-up ──
{ name:"Bluff — Twin Rocks Trading Post", county:"San Juan, UT", emoji:"🪨", lat:37.2836, lon:-109.5497, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Twin Rocks Trading Post in Bluff operates in the shadow of two dramatic sandstone spires and has been a source of <em>authentic Navajo rugs, pottery, and jewelry</em> since 1989. The trading post continues the tradition of cultural and commercial exchange between the Navajo Nation and outside buyers that has sustained artisan traditions in the Four Corners region for over a century." },
{ name:"Bears Ears — Arch Canyon", county:"San Juan, UT", emoji:"🌉", lat:37.5500, lon:-109.7500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Arch Canyon cuts through Cedar Mesa and contains both a large natural arch and <em>numerous Ancestral Puebloan cliff dwellings</em> built between 1000 and 1300 CE in the canyon walls. The canyon's combination of geological drama and archaeological richness makes it one of the most rewarding canyon hikes in the Bears Ears region." },
{ name:"Monument Valley — Rain God Mesa", county:"San Juan, UT", emoji:"⛈", lat:37.0100, lon:-110.1500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Rain God Mesa is a large flat-topped butte within Monument Valley that serves as the backdrop for some of John Ford's most dramatic compositions in <em>The Searchers and Fort Apache</em>, its sheer walls providing a scale reference that makes the human figures in the foreground appear tiny against the landscape. The Navajo consider Rain God Mesa one of the most sacred formations in the valley." },
{ name:"Canyonlands — Upheaval Dome", county:"San Juan, UT", emoji:"🌋", lat:38.4325, lon:-109.9222, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Upheaval Dome is a mysterious circular feature in Canyonlands that geologists debated for decades — it was either formed by a <em>meteorite impact or a collapsed salt dome</em>, and recent evidence suggests the meteor theory is correct, making it one of the few confirmed impact craters in Utah. The two-mile hike to the first overlook offers one of the most scientifically fascinating geological views in any national park." },
{ name:"Valley of the Gods — Seven Sailors Formation", county:"San Juan, UT", emoji:"⛵", lat:37.2500, lon:-109.9800, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Seven Sailors formation in Valley of the Gods is a cluster of sandstone buttes that rise like a fleet of ships from the desert floor, and the BLM-managed valley around them offers the <em>Monument Valley experience without the entrance fee</em> or tour requirements. The valley's 17-mile dirt road is one of the finest scenic drives in Utah for those willing to trade pavement for solitude." },
{ name:"San Juan River — River Expedition Route", county:"San Juan, UT", emoji:"🚣", lat:37.1500, lon:-110.0000, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The 84-mile San Juan River float from Mexican Hat to Clay Hills Crossing passes through <em>1,000-foot canyon walls</em> containing the most complete sequence of geological formations in the Colorado Plateau, with rock layers representing over 300 million years of Earth history visible in a single canyon cross-section. The river trip passes dozens of Ancestral Puebloan sites and is considered one of the premier archaeological river journeys in North America." },
{ name:"White Mesa Ute Community", county:"San Juan, UT", emoji:"🪶", lat:37.5400, lon:-109.4800, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"White Mesa is the southernmost community of the <em>Ute Mountain Ute Tribe</em>, whose ancestors have occupied the Colorado Plateau for at least 1,000 years and whose land was drastically reduced by a series of treaties and executive orders in the 19th century. The community maintains traditional cultural practices including the Bear Dance, one of the oldest continuous ceremonial traditions in the American Southwest." },
{ name:"Four Corners — Navajo Nation Welcome Center", county:"San Juan, UT", emoji:"🗺", lat:36.9991, lon:-109.0452, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Four Corners monument, operated by the Navajo Nation, draws over <em>250,000 visitors annually</em> to the only point in America where four states meet — making it one of the most visited destinations in the Navajo Nation. The surrounding market of Navajo artists selling jewelry, rugs, and pottery provides direct economic benefit to tribal members and preserves craft traditions threatened by mass-produced imitations." },
{ name:"Bears Ears — Owl Creek Canyon", county:"San Juan, UT", emoji:"🦉", lat:37.4833, lon:-109.7833, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Owl Creek Canyon contains one of the finest collections of <em>intact Ancestral Puebloan cliff dwellings</em> remaining in the Bears Ears region, where multi-story stone structures cling to canyon walls in remarkable preservation. The canyon's remote location means that most visitors see only a small fraction of the archaeological sites, and new discoveries are still being made by archaeologists working in the area." },
{ name:"Monument Valley — East Mitten Butte", county:"San Juan, UT", emoji:"🧤", lat:36.9950, lon:-110.0950, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"The East Mitten Butte, with its distinctive 'thumb' of rock rising alongside the main butte, has been the <em>primary foreground element</em> in more Monument Valley photographs and film compositions than any other single formation. The butte's shadow-play at different times of day and in different weather conditions creates an infinite variety of visual effects that have challenged and delighted photographers for a century." },

// ── Grand County final top-up ──
{ name:"Arches — Balanced Rock", county:"Grand, UT", emoji:"⚖️", lat:38.7014, lon:-109.5644, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Balanced Rock consists of a <em>3,577-ton boulder</em> perched atop a narrow 73-foot pedestal of eroding mudstone — the boulder itself is the size of three school buses stacked on top of each other. The formation has been used in film and television productions as a symbol of precarious balance, and geologists have calculated that the pedestal has been eroding at a rate that will topple it within a few thousand years." },
{ name:"Arches — Double Arch", county:"Grand, UT", emoji:"🌉", lat:38.6892, lon:-109.5344, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Double Arch is technically two arches sharing a common foundation — one spanning <em>148 feet and the other 112 feet</em> — creating one of the most photographically dramatic formations in Arches. The arches were formed not by water erosion but by 'pothole weathering' — water collecting in depressions in the rock and chemically dissolving the sandstone from below." },
{ name:"Moab — Slickrock Bike Trail", county:"Grand, UT", emoji:"🚵", lat:38.5500, lon:-109.5100, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab's Slickrock Bike Trail, developed in 1969, was the <em>first purpose-built mountain bike trail in America</em> and remains one of the most challenging and celebrated — a 10-mile loop across Navajo sandstone domes with grades up to 30% and sheer drop-offs that test even expert riders. The trail's popularity single-handedly established Moab as the mountain biking capital of the world." },
{ name:"Professor Creek — Mary Jane Canyon", county:"Grand, UT", emoji:"🌊", lat:38.6700, lon:-109.3900, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Mary Jane Canyon, accessible by wading up Professor Creek, is one of the <em>finest slot canyon hikes</em> in the Moab area — a narrow corridor of red and orange sandstone sculpted by flash floods into smooth, undulating walls that glow in the reflected light. The canyon's end opens into a chamber where light pools on the canyon floor in patterns that photographers travel thousands of miles to capture." },
{ name:"Moab — Arches Visitor Center Historic Site", county:"Grand, UT", emoji:"🏛", lat:38.6861, lon:-109.6189, cat:"Historic Building", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Arches Visitor Center was designed by architect Herbert Maier in the <em>National Park Service Rustic style</em> of the 1950s, using native sandstone and massive wooden beams to create a building that feels grown from the landscape rather than imposed upon it. The center's interpretive exhibits explain the geological processes that created 2,000+ arches in this single park." },
{ name:"Colorado River — Westwater Canyon Rafting", county:"Grand, UT", emoji:"🚣", lat:38.8228, lon:-109.1869, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Westwater Canyon on the Colorado River contains the <em>oldest exposed rock in Utah</em> — 1.7-billion-year-old Vishnu schist that was once the core of an ancient mountain range — visible in the canyon walls as black and pink banded cliffs. The canyon's Class IV-V rapids make it one of the premier one-day whitewater runs in the Colorado River system." },
{ name:"Moab — Corona Arch Trail", county:"Grand, UT", emoji:"👑", lat:38.5731, lon:-109.6256, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Corona Arch, accessible via a 3-mile round-trip trail along the Colorado River, has a <em>140-foot span</em> large enough to fly a helicopter through — which someone famously did in a video that went viral and temporarily closed the arch to base jumpers and rope swingers. The arch's scale and accessibility make it one of the most visited natural arches outside Arches National Park." },
{ name:"Kane Creek Canyon — Dinosaur Tracks", county:"Grand, UT", emoji:"🦕", lat:38.5200, lon:-109.5600, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Kane Creek Canyon contains one of the largest exposed <em>Jurassic dinosaur trackways</em> in Utah — hundreds of three-toed footprints pressed into ancient mudstone by carnivorous therapods stalking the banks of a prehistoric river 150 million years ago. The tracks are visible from the canyon road and accessible without a hike, making them one of the most convenient paleontological sites in the Moab area." },
{ name:"Moab Giants — Fossil Discovery Exhibit", county:"Grand, UT", emoji:"🦴", lat:38.5869, lon:-109.5781, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Moab area's Morrison Formation has produced some of the <em>most significant dinosaur discoveries in paleontology history</em>, including multiple Stegosaurus, Brachiosaurus, and Allosaurus specimens that formed the basis for our understanding of Jurassic-era ecosystems. Active quarrying continues in the region today, and new species are still being named from specimens found in Grand County's ancient rock layers." },
{ name:"Dead Horse Point — Mountain Bike Trail", county:"Grand, UT", emoji:"🚵", lat:38.4900, lon:-109.7500, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Intrepid Trail System at Dead Horse Point offers <em>15 miles of world-class mountain biking</em> on the mesa top with views of Canyonlands and the Colorado River that make it one of the most scenic cycling destinations in America. The trail system's accessible design allows riders of varying ability to experience the mesa's extraordinary views without the technical difficulty of the canyon country trails below." },
{ name:"Moab — Behind the Rocks 4WD Trail", county:"Grand, UT", emoji:"🚙", lat:38.4700, lon:-109.5300, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Behind the Rocks is home to the legendary Fins and Things trail — one of the most technically demanding <em>4WD routes in North America</em>, where vehicles climb near-vertical sandstone fins and traverse ledges with thousand-foot drop-offs. The trail has appeared in numerous off-road vehicle films and documentaries and its difficulty has become the benchmark against which other 4WD challenges are measured." },

// ── Mohave County top-up to 70 ──
{ name:"Topock Maze — Ancient Geoglyph", county:"Mohave, AZ", emoji:"🗿", lat:34.7000, lon:-114.4800, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Topock Maze, or Mystic Maze, is a <em>6,000-year-old geoglyph</em> covering 18 acres of Colorado River floodplain — a vast pattern of cleared pathways and piled gravel created by the Mohave and Quechan peoples whose spiritual significance has never been fully decoded. The maze is visible from the air and is one of the oldest and largest Native American ceremonial sites in the Southwest." },
{ name:"Bullhead City — Laughlin Bridge Colorado River Crossing", county:"Mohave, AZ", emoji:"🌉", lat:35.1478, lon:-114.5686, cat:"Landmark", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Laughlin Bridge spanning the Colorado River connects Laughlin, Nevada to Bullhead City, Arizona — the <em>only river crossing</em> for 60 miles in either direction. The bridge's position at the heart of the Laughlin casino district means it carries more cross-state pedestrian traffic than almost any rural bridge in America, with gamblers and resort guests crossing constantly between the two states." },
{ name:"Havasu National Wildlife Refuge — Pintail Slough", county:"Mohave, AZ", emoji:"🦢", lat:34.6200, lon:-114.4600, cat:"Wildlife Refuge", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Pintail Slough within the Havasu National Wildlife Refuge is one of the <em>finest winter waterfowl concentrations</em> in the lower Colorado River corridor, where pintails, wigeons, and canvasbacks gather by the thousands in the managed marsh habitat. The slough's name reflects the historic abundance of pintail ducks that once darkened the sky above the Colorado River valley during migration." },
{ name:"Chloride — Roy Purcell Murals", county:"Mohave, AZ", emoji:"🎨", lat:35.4092, lon:-114.2064, cat:"Arts", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Roy Purcell's massive murals painted directly onto the granite boulders above Chloride in 1966 are some of the <em>most ambitious outdoor public art works</em> in the American Southwest — swirling figures covering hundreds of square feet of rock face in vivid colors that have survived six decades of desert sun. Purcell returned in 2009 to restore and repaint the murals, calling them his life's primary artistic statement." },
{ name:"Lake Havasu — Swansea Ghost Town", county:"Mohave, AZ", emoji:"🏚", lat:34.2378, lon:-114.1286, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Swansea is one of the most intact copper mining ghost towns in Arizona, where <em>adobe walls, brick smelter ruins, and scattered mining equipment</em> from a 1908-1924 boom period still stand in the desert above the Arrastra Creek drainage. The ghost town's remoteness — 35 miles from the nearest paved road — has protected it from vandalism and the buildings are among the finest surviving examples of early Arizona industrial architecture." },
{ name:"Kingman — Westside Lilo's Cafe Route 66", county:"Mohave, AZ", emoji:"🍔", lat:35.1894, lon:-114.0700, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's surviving Route 66 diners and cafes preserve the <em>roadside food culture</em> that sustained travelers crossing the Mojave Desert from the 1930s through the 1970s, when the interstate bypassed the town and froze its commercial strip in amber. The surviving establishments have become pilgrimage sites for Route 66 enthusiasts who seek the authentic experience of America's original road trip culture." },
{ name:"Mohave Valley — Fort Mohave Indian Tribe Cultural Center", county:"Mohave, AZ", emoji:"🪶", lat:34.9200, lon:-114.5600, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Hoover_Dam%2C_Nevada_and_Arizona.jpg/320px-Hoover_Dam_Nevada_and_Arizona.jpg", fact:"The Fort Mojave Indian Tribe Cultural Center preserves the heritage of the <em>Mohave people</em> — one of the few Native American nations never militarily defeated — whose territory spanned the lower Colorado River valley for 2,000 years. The tribe's distinctive pottery, beadwork, and oral traditions are maintained through programs at the cultural center that serves the 1,500-member tribal community." },
{ name:"Grand Canyon West — Eagle Point Overlook", county:"Mohave, AZ", emoji:"🦅", lat:36.0200, lon:-113.8200, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Eagle Point on the Hualapai Reservation offers a <em>4,000-foot sheer drop</em> into the Grand Canyon from a promontory shaped like an eagle with wings spread — a natural formation the Hualapai consider sacred. The overlook is the site of the famous Skywalk glass bridge and is the only place on the South Rim where visitors can descend to the Colorado River by vehicle." },
{ name:"Dolan Springs — Chloride Road Scenic Byway", county:"Mohave, AZ", emoji:"🛤", lat:35.5950, lon:-114.2600, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Chloride Road Scenic Byway passes through high Mojave Desert terrain where <em>Joshua trees mix with granite outcroppings</em> and panoramic views of the Colorado River valley 3,000 feet below stretch to Nevada and California. The byway connects Kingman to the historic mining towns of Chloride and Dolan Springs through landscapes that have been largely bypassed by interstate highway development." },
{ name:"Lake Havasu City — Rotary Community Park", county:"Mohave, AZ", emoji:"🌳", lat:34.4839, lon:-114.3286, cat:"Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/London_Bridge_Lake_Havasu_City.jpg/320px-London_Bridge_Lake_Havasu_City.jpg", fact:"Lake Havasu City's Rotary Community Park sits beside the London Bridge Channel and offers the classic view of the <em>transplanted London Bridge</em> framed by the surrounding desert mountains — one of the most surreal juxtapositions of Old World architecture and American Southwest landscape anywhere in the world. The park's sandy beach and palm trees create the impression of a Mediterranean resort transplanted to the Mojave." },
{ name:"Mohave Desert — Historic Beale Springs Camp", county:"Mohave, AZ", emoji:"💧", lat:35.2500, lon:-114.0000, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Beale Springs, two miles north of Kingman, was a <em>critical water source on the Beale Wagon Road of 1857</em> and later served as a military fort, a Walapai Indian Agency, and a ranch before being absorbed into the expanding city. Lieutenant Beale's camel experiment stopped here and the springs' cottonwood trees provided the only shade for miles in the blazing Mojave summer." },
{ name:"Kingman — Historic Route 66 Neon Signs", county:"Mohave, AZ", emoji:"✨", lat:35.1894, lon:-114.0530, cat:"Historic District", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"Kingman's surviving neon signs from the Route 66 era represent some of the <em>finest examples of mid-20th century roadside commercial art</em> still illuminated in the Southwest, including the iconic Arcadia Lodge sign that has welcomed travelers since 1938. The signs' preservation has made Kingman a reference point for neon restoration artists and graphic designers studying the visual culture of American road travel." },
{ name:"Katherine Mine — Oatman District", county:"Mohave, AZ", emoji:"⛏", lat:34.8500, lon:-114.4000, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Katherine Mine south of Oatman produced <em>$1.8 million in gold</em> during its peak years and was the largest gold producer in Mohave County during the early 20th century. The mine's headframe and mill foundations still stand above the Colorado River valley and are visible from the historic highway that connected the mining camps to the outside world." },
{ name:"Black Mountains — Sitgreaves Pass Vista", county:"Mohave, AZ", emoji:"🏔", lat:34.9000, lon:-114.3500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Route_66_shield.svg/320px-Route_66_shield.svg.png", fact:"The Black Mountains of western Arizona are one of the <em>most volcanic landscapes</em> in the Southwest — a series of ancient lava flows and cinder cones that created the dramatic backdrop for the most treacherous section of Route 66. The mountains' dark basalt contrasts dramatically with the red and orange desert below, creating a visual starkness that photographers and filmmakers have used to evoke the edge of the world." },
{ name:"Mohave County — Santa Claus Arizona Ghost Town", county:"Mohave, AZ", emoji:"🎅", lat:35.3167, lon:-114.1000, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Santa Claus, Arizona was a <em>planned Christmas-themed tourist town</em> built in 1937 by a real estate promoter who hoped the name would attract buyers to his desert subdivision. The scheme failed and the town was essentially abandoned by the 1970s, leaving behind a ghost town of Christmas-themed building names in the Mohave Desert that has become one of the most photographed roadside curiosities in Arizona." },

// ── San Juan County top-up to 70 ──
{ name:"Monument Valley — North Window Arch", county:"San Juan, UT", emoji:"🌅", lat:37.0050, lon:-110.0950, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"North Window in Monument Valley frames a <em>perfect view of the Mittens buttes</em> through a natural sandstone arch on the valley's North Rim — one of the most sought-after photographic compositions in the American Southwest. The arch is accessible on guided Navajo Nation tours only, its access controlled to protect both the site and its spiritual significance to the Diné people." },
{ name:"Bears Ears — Butler Wash Overlook", county:"San Juan, UT", emoji:"🏺", lat:37.4200, lon:-109.7600, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Butler Wash Overlook provides a dramatic view of a <em>13th-century cliff dwelling</em> built into an alcove in the Comb Ridge sandstone across the canyon — a village of over 20 rooms and four kivas whose inhabitants abandoned it around 1270 CE during the great Ancestral Puebloan migration. The overlook's accessibility and the dwelling's remarkable state of preservation make it one of the most visited archaeological sites in San Juan County." },
{ name:"Blanding — Dinosaur trackway site", county:"San Juan, UT", emoji:"🦶", lat:37.6200, lon:-109.4800, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Morrison Formation outcropping near Blanding contains <em>dinosaur trackways and bone fragments</em> eroding from the Jurassic-era rock at multiple accessible sites that have provided some of the finest specimens in the Edge of the Cedars State Park museum. The formation's exposure across thousands of square miles of San Juan County makes this region one of the most productive areas for dinosaur paleontology in North America." },
{ name:"Canyonlands — Chesler Park", county:"San Juan, UT", emoji:"🏕", lat:38.1800, lon:-109.8000, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Chesler Park in Canyonlands' Needles District is a <em>hidden meadow surrounded by red and white striped spires</em> accessible only by an 11-mile round-trip hike or backpacking route through some of the most dramatic canyon country in Utah. The park is considered one of the finest backcountry destinations in the National Park System, with a Joint Trail loop that passes through a 50-foot rock joint barely wide enough for a hiker's shoulders." },
{ name:"Monument Valley — Mystery Valley", county:"San Juan, UT", emoji:"🗿", lat:36.9500, lon:-110.1500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Mystery Valley, accessible only on guided Navajo Nation jeep tours, contains over <em>100 Ancestral Puebloan sites</em> including cliff dwellings, petroglyphs, and burial sites spread across a hidden canyon system adjacent to Monument Valley. The valley's combination of dramatic sandstone scenery and archaeological richness makes it one of the most complete cultural landscape experiences available in the Four Corners region." },
{ name:"San Juan County — Recapture Lodge Historic", county:"San Juan, UT", emoji:"🏨", lat:37.2836, lon:-109.5497, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Recapture Lodge in Bluff has been a base camp for canyon country explorers, archaeologists, and river guides since it opened in <em>1959</em>, hosting everyone from academic researchers to the rafters who pioneered the San Juan River route. The lodge's founder, Jim Rigg, was one of the first people to run the San Juan River through the canyons and his family operated the lodge for three generations." },
{ name:"Bears Ears — Road Canyon", county:"San Juan, UT", emoji:"🏺", lat:37.5000, lon:-109.8500, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Road Canyon on Cedar Mesa contains some of the <em>most photographically dramatic cliff dwellings</em> in the Bears Ears region, where multi-story stone structures cling to sheer sandstone walls in positions that seem to defy gravity. The canyon requires a full day hike with route-finding skills and a permit, limiting access in a way that preserves the site's pristine condition and sense of discovery." },
{ name:"Comb Ridge — Wolfman Panel Petroglyphs", county:"San Juan, UT", emoji:"🪨", lat:37.4000, lon:-109.6800, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Wolfman Panel on Comb Ridge is one of the finest <em>Basketmaker-era petroglyph panels</em> in the Southwest, featuring large anthropomorphic figures with elaborate headdresses carved into the sandstone around 500 CE. The panel's bold figures and the dramatic setting of the Comb Ridge escarpment make it one of the most evocative and widely photographed archaeological sites in San Juan County." },
{ name:"Valley of the Gods — Lady in the Bathtub", county:"San Juan, UT", emoji:"🛁", lat:37.3000, lon:-109.9200, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Lady in the Bathtub is one of Valley of the Gods' most recognizable sandstone formations — a narrow butte with a rounded depression near its top that <em>perfectly resembles a person reclining in a bath</em>. The formation has been used in automobile commercials and off-road vehicle promotions as the defining image of the remote, otherworldly landscape of the San Juan County canyon country." },
{ name:"Navajo Nation — Monument Valley Visitor Center", county:"San Juan, UT", emoji:"🏛", lat:36.9980, lon:-110.0985, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"The Monument Valley Navajo Tribal Park Visitor Center, perched on the canyon rim above the valley floor, offers the <em>most iconic view of the Mittens and Merrick Butte</em> in existence — the same composition used in Stagecoach, The Searchers, and dozens of other films. The center's exhibits explain the Navajo cultural significance of the formations and the history of Hollywood's relationship with the valley." },
{ name:"Bluff — San Juan Hill Historic Wagon Route", county:"San Juan, UT", emoji:"🛤", lat:37.2950, lon:-109.5600, cat:"Historic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"San Juan Hill above Bluff was where the <em>1880 Mormon pioneer expedition</em> faced its most desperate moment — after successfully lowering wagons through the Hole-in-the-Rock, they still faced a near-vertical sandstone hill that had to be conquered before reaching the San Juan River valley. The pioneers' solution — building a road on the cliff face by hand with iron tools — remains one of the most remarkable feats of pioneer engineering in American history." },
{ name:"Monument Valley — John Wayne's Dining Room", county:"San Juan, UT", emoji:"🎬", lat:37.0061, lon:-110.2156, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Monument_Valley_Navajo_Tribal_Park.jpg/320px-Monument_Valley_Navajo_Tribal_Park.jpg", fact:"Goulding's Lodge preserves the <em>original dining room where John Wayne, Henry Fonda, and John Ford</em> ate their meals during the filming of Stagecoach, Fort Apache, and She Wore a Yellow Ribbon — a simple room whose walls are covered with photographs and memorabilia from the golden age of Monument Valley filmmaking. The adjacent museum contains the actual camera equipment Ford used and Navajo artifacts from the performers who appeared in his films." },
{ name:"Canyonlands — Druid Arch", county:"San Juan, UT", emoji:"🏛", lat:38.1400, lon:-109.8300, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Druid Arch in Canyonlands' Needles District is a massive stone formation that resembles <em>ancient megalithic standing stones</em> — its resemblance to Stonehenge gave it its name. The 11-mile round-trip hike to reach it passes through some of the finest canyon scenery in the Needles District and the arch's remote location means it sees far fewer visitors than the arches in the national park bearing that name." },

// ── Grand County top-up to 70 ──
{ name:"Moab — Red Cliffs Lodge Film Location", county:"Grand, UT", emoji:"🎬", lat:38.6500, lon:-109.4200, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Red Cliffs Lodge on the Colorado River has hosted <em>film crews since the 1940s</em> and operates a free movie museum documenting over 70 years of production in the Moab area, including original props, costumes, and photographs from Thelma and Louise, Indiana Jones, and City Slickers. The lodge's riverside location provides one of the most dramatic filming backdrops in the American Southwest." },
{ name:"Arches — Fiery Furnace", county:"Grand, UT", emoji:"🔥", lat:38.7453, lon:-109.5678, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Fiery Furnace is a labyrinth of <em>narrow sandstone fins and passages</em> that glow red and orange in the late afternoon sun — a disorienting maze that requires a ranger-guided tour because visitors regularly get lost attempting it alone. The formation has been used in film productions seeking an alien or hellish landscape, its narrow corridors and towering fins creating claustrophobic drama impossible to recreate artificially." },
{ name:"Colorado River — Moab Daily Rafting", county:"Grand, UT", emoji:"🚣", lat:38.5500, lon:-109.5800, cat:"Recreation", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Colorado River through Moab Valley offers family-friendly <em>half-day and full-day rafting trips</em> through red rock canyon scenery accessible to all ages, making it one of the most popular outdoor activities in Utah. The calm water section above Cataract Canyon allows paddlers to float beneath 500-foot canyon walls while Bald Eagles nest in the cottonwood trees along the shore." },
{ name:"Moab — Arches National Park Night Sky Program", county:"Grand, UT", emoji:"🌌", lat:38.7331, lon:-109.5925, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Arches National Park is designated an <em>International Dark Sky Park</em>, offering some of the finest stargazing in the American West from locations where natural arches frame the Milky Way in compositions that have become among the most reproduced astrophotography images ever taken. The park's ranger-led night sky programs have introduced thousands of visitors to the cosmos visible from the Colorado Plateau's mile-high elevation and clean desert air." },
{ name:"Grand County — Moab Museum", county:"Grand, UT", emoji:"🏛", lat:38.5733, lon:-109.5498, cat:"Museum", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Moab Museum tells the complete story of Grand County from its <em>Ancestral Puebloan and Fremont origins</em> through the uranium boom and into the outdoor recreation era, preserving the cultural memory of one of the most dramatically transformed communities in the American West. The museum's collection includes uranium mining equipment, pioneer artifacts, and geological specimens that explain the forces that created the canyon country landscape." },
{ name:"Arches — Sand Dune Arch", county:"Grand, UT", emoji:"🏜", lat:38.7647, lon:-109.5814, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Sand Dune Arch sits in a sheltered alcove where <em>deep red sand accumulates</em> in a natural bowl beneath the arch's span, creating one of the most photogenic spots in Arches and a favorite of families with children who can play in the sand. The arch's sheltered location makes it one of the coolest spots in the park on hot summer days." },
{ name:"Moab — Tower Ruin Hike", county:"Grand, UT", emoji:"🏺", lat:38.5200, lon:-109.4800, cat:"Archaeological Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"The Tower Ruin near Moab is an <em>Ancestral Puebloan round tower</em> built around 1200 CE in a canyon alcove visible from below but requiring a technical scramble to reach — an adventure that rewards hikers with one of the finest examples of prehistoric masonry in the Moab area. The tower's location and construction quality suggest it served as both a watchtower and a storage facility for the farming community that built it." },
{ name:"Canyonlands — Green River Overlook", county:"Grand, UT", emoji:"🌊", lat:38.4200, lon:-109.9000, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Green River Overlook in Canyonlands offers a <em>bird's-eye view of the Green River</em> 1,200 feet below as it meanders through sweeping bends toward its confluence with the Colorado River — a panorama that captures the essence of the Colorado Plateau's canyon country in a single vista. The overlook is accessible by paved road and is considered one of the finest drive-to viewpoints in the National Park System." },
{ name:"Moab — Hole in the Rock Restaurant Historic Route", county:"Grand, UT", emoji:"🍔", lat:38.5733, lon:-109.5498, cat:"Historic Site", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Delicate_Arch_LaSal_Mountains.jpg/320px-Delicate_Arch_LaSal_Mountains.jpg", fact:"Moab's historic diners and food culture developed around the <em>uranium mining boom of the 1950s</em> when the town needed to feed thousands of prospectors and workers, and several establishments from that era still operate on Main Street. The town's food scene has since evolved into one of the finest in rural Utah, driven by the outdoor recreation tourism that replaced the mining economy." },
{ name:"Colorado River — Meander Canyon Overlook", county:"Grand, UT", emoji:"🏜", lat:38.3800, lon:-109.8500, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Meander Canyon, where the Colorado River makes a <em>series of sweeping bends</em> visible from the canyon rim 1,500 feet above, is one of the finest examples of entrenched river meanders in the world — formed when the river's ancient course was locked in place and then slowly cut downward as the Colorado Plateau uplifted around it. The canyon's sinuous path through the red rock desert is one of the most recognizable aerial images of Utah." },
{ name:"Moab — Murphy Point Trail Canyonlands", county:"Grand, UT", emoji:"⛰", lat:38.4100, lon:-109.8600, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Murphy Point in Canyonlands' Island in the Sky district offers a <em>360-degree panoramic view</em> from a promontory that juts out over the White Rim 1,000 feet below, with the La Sal Mountains, the Needles, and the canyon country stretching to the horizon in every direction. The 3.6-mile round-trip trail is considered one of the finest moderate hikes in the National Park System." },

// ── Kane County top-up to 70 ──
{ name:"Zion — Canyon Overlook Trail", county:"Kane, UT", emoji:"👁", lat:37.2200, lon:-112.9000, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Canyon Overlook Trail in Zion's East Section offers the <em>best view of Zion Canyon</em> for the least effort — a 1-mile round-trip walk through a slot canyon and along ledges that ends at a panoramic overlook 1,000 feet above the canyon floor. The trail's dramatic exposure and canyon views make it one of the most photographed short hikes in any national park." },
{ name:"Zion — Weeping Rock Trail", county:"Kane, UT", emoji:"💧", lat:37.2583, lon:-112.9469, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"Weeping Rock in Zion Canyon is a <em>spring-fed alcove</em> where water seeps through the Navajo sandstone and drips from the ceiling of an overhang, creating a hanging garden of columbine, shooting stars, and scarlet monkeyflower that blooms from April through October. The spring's water fell as rain over 4,000 years ago and has been slowly percolating through the sandstone ever since." },
{ name:"Bryce Canyon — Fairyland Loop", county:"Kane, UT", emoji:"🧚", lat:37.6600, lon:-112.1400, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"The Fairyland Loop is Bryce Canyon's most dramatic hike — an 8-mile circuit that descends into the heart of the hoodoo forest and passes formations so fantastically eroded that <em>early visitors compared them to fairy tale illustrations</em>. The loop's namesake canyon contains the densest concentration of hoodoos in the park and passes Tower Bridge, a double arch reminiscent of London's famous bridge." },
{ name:"Grand Staircase — Wahweap Hoodoos", county:"Kane, UT", emoji:"🏜", lat:37.0000, lon:-111.7000, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Wahweap Hoodoos near Lake Powell are a field of <em>white Entrada sandstone spires</em> topped with dark brown capstones — a distinctive two-tone formation not seen anywhere else in the Grand Staircase. The hoodoos require a 6-mile round-trip hike across open desert to reach, and their remote location and otherworldly appearance have made them an increasingly popular destination for photographers seeking unusual landscape subjects." },
{ name:"Kanab — Little Hollywood Land Museum", county:"Kane, UT", emoji:"🎬", lat:37.0475, lon:-112.5263, cat:"Movie & TV Film", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The Little Hollywood Land Museum in Kanab documents the town's extraordinary <em>film history spanning 100 years</em>, with exhibits dedicated to the stars, directors, and Navajo and Paiute performers who made the area one of the most productive outdoor film locations in American cinema history. The museum's collection of autographed photographs, props, and memorabilia from hundreds of productions is one of the finest archives of Western film culture in existence." },
{ name:"Zion — Court of the Patriarchs", county:"Kane, UT", emoji:"🏛", lat:37.2511, lon:-112.9600, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Court of the Patriarchs — three massive sandstone peaks named Abraham, Isaac, and Jacob — were named in 1916 by a Methodist minister who saw in their grandeur a <em>reflection of Old Testament majesty</em>. The formation's dramatic vertical faces rising 3,500 feet from the canyon floor are visible from the main Zion Canyon road and are among the first formations to catch the morning light as the sun rises over the canyon rim." },
{ name:"Bryce Canyon — Natural Bridge", county:"Kane, UT", emoji:"🌉", lat:37.5750, lon:-112.1950, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Bryce_Canyon_hoodoos_Amphitheater.jpg/320px-Bryce_Canyon_hoodoos_Amphitheater.jpg", fact:"Bryce Canyon's Natural Bridge is technically a <em>natural arch</em> rather than a bridge — formed by weathering rather than by water flowing through it — spanning 85 feet across a void between two cliff faces. The formation is one of the most photographed natural arches in Utah and is accessible from a roadside pullout, making it one of the most convenient geological wonders in the park." },
{ name:"Grand Staircase — Deer Creek Road", county:"Kane, UT", emoji:"🦌", lat:37.8000, lon:-111.6500, cat:"Scenic Route", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"Deer Creek Road through the heart of Grand Staircase-Escalante passes through <em>remote canyon country</em> where the road conditions change with every rainstorm and cell phone service ends at the pavement. The route connects Escalante to Boulder through landscape so remote that it was the last area of the contiguous United States to be mapped from the ground, with the final topographic survey completed in the 1970s." },
{ name:"Zion — Riverside Walk", county:"Kane, UT", emoji:"🌊", lat:37.3622, lon:-112.9472, cat:"National Park", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Grand_Canyon_from_South_Rim_-_Oct_2012.jpg/320px-Grand_Canyon_from_South_Rim_-_Oct_2012.jpg", fact:"The Riverside Walk is the paved entry to the Zion Narrows — a 2-mile stroll along the Virgin River that transforms from a gentle canyon walk into the <em>dramatic slot canyon entrance</em> where the walls close in and the river becomes the trail. The walk is one of the most accessible and rewarding short hikes in any national park, ending at the point where casual visitors turn back and serious hikers wade into the canyon." },
{ name:"Kanab — Peekaboo Slot Canyon Tours", county:"Kane, UT", emoji:"🌈", lat:37.0475, lon:-112.5263, cat:"Natural Feature", photo:"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Valley_of_Fire_State_Park.jpg/320px-Valley_of_Fire_State_Park.jpg", fact:"The slot canyons surrounding Kanab, including Peek-a-Boo and Spooky Gulch, are among the <em>most colorful and accessible slot canyons</em> in the Grand Staircase region — narrow passages of swirling pink and orange sandstone worn smooth by flash floods over millions of years. The canyons' accessibility from Kanab has made the town a hub for slot canyon guided tours attracting visitors from around the world." }

];
